```typescript
// ============================================================
// SERVER: trpc/router.ts
// ============================================================
import { initTRPC, TRPCError } from '@trpc/server';
import { z } from 'zod';

const t = initTRPC.context<{ userId: string }>().create();

export const router     = t.router;
export const publicProcedure    = t.procedure;
export const protectedProcedure = t.procedure.use(({ ctx, next }) => {
  if (!ctx.userId) throw new TRPCError({ code: 'UNAUTHORIZED' });
  return next({ ctx: { userId: ctx.userId } });
});

// Zod schemas
const TodoSchema = z.object({
  id:        z.string().uuid(),
  title:     z.string().min(1).max(200),
  completed: z.boolean(),
  createdAt: z.date(),
});

const CreateTodoInput = z.object({
  title: z.string().min(1, 'Title is required').max(200),
});

const UpdateTodoInput = z.object({
  id:        z.string().uuid(),
  title:     z.string().min(1).max(200).optional(),
  completed: z.boolean().optional(),
});

export type Todo = z.infer<typeof TodoSchema>;

// In-memory store (replace with DB)
const store = new Map<string, Todo[]>(); // userId -> todos

export const todoRouter = router({
  list: protectedProcedure.query(({ ctx }) => {
    return store.get(ctx.userId) ?? [];
  }),

  create: protectedProcedure
    .input(CreateTodoInput)
    .mutation(({ ctx, input }) => {
      const todo: Todo = {
        id:        crypto.randomUUID(),
        title:     input.title,
        completed: false,
        createdAt: new Date(),
      };
      const todos = store.get(ctx.userId) ?? [];
      store.set(ctx.userId, [...todos, todo]);
      return todo;
    }),

  update: protectedProcedure
    .input(UpdateTodoInput)
    .mutation(({ ctx, input }) => {
      const todos = store.get(ctx.userId) ?? [];
      const idx = todos.findIndex(t => t.id === input.id);
      if (idx === -1) throw new TRPCError({ code: 'NOT_FOUND' });
      const updated = { ...todos[idx], ...input };
      todos[idx] = updated;
      store.set(ctx.userId, todos);
      return updated;
    }),

  delete: protectedProcedure
    .input(z.object({ id: z.string().uuid() }))
    .mutation(({ ctx, input }) => {
      const todos = store.get(ctx.userId) ?? [];
      store.set(ctx.userId, todos.filter(t => t.id !== input.id));
      return { success: true };
    }),
});

export const appRouter = router({ todos: todoRouter });
export type AppRouter = typeof appRouter;

// ============================================================
// CLIENT: TodoList.tsx (React Query + tRPC)
// ============================================================
import { trpc } from './trpc-client'; // your trpc client setup

export function TodoList() {
  const utils = trpc.useUtils();
  const { data: todos = [] } = trpc.todos.list.useQuery();

  const createMutation = trpc.todos.create.useMutation({
    // Optimistic update
    onMutate: async (input) => {
      await utils.todos.list.cancel();
      const previous = utils.todos.list.getData();

      utils.todos.list.setData(undefined, old => [
        ...(old ?? []),
        { id: `temp-${Date.now()}`, title: input.title, completed: false, createdAt: new Date() },
      ]);

      return { previous }; // rollback context
    },
    onError: (_, __, ctx) => {
      utils.todos.list.setData(undefined, ctx?.previous);
    },
    onSettled: () => utils.todos.list.invalidate(),
  });

  const toggleMutation = trpc.todos.update.useMutation({
    onMutate: async (input) => {
      await utils.todos.list.cancel();
      const previous = utils.todos.list.getData();
      utils.todos.list.setData(undefined, old =>
        old?.map(t => t.id === input.id ? { ...t, ...input } : t)
      );
      return { previous };
    },
    onError: (_, __, ctx) => utils.todos.list.setData(undefined, ctx?.previous),
    onSettled: () => utils.todos.list.invalidate(),
  });

  return (
    <ul>
      {todos.map(todo => (
        <li key={todo.id}>
          <input
            type="checkbox"
            checked={todo.completed}
            onChange={() => toggleMutation.mutate({ id: todo.id, completed: !todo.completed })}
          />
          {todo.title}
        </li>
      ))}
      <button onClick={() => createMutation.mutate({ title: 'New todo' })}>Add</button>
    </ul>
  );
}
```

**tRPC advantages over REST:** Zero-cost type sharing — the `AppRouter` type is imported by the client, so mismatched API calls are TypeScript compile errors. Zod validation runs on both input parsing and type inference. Optimistic updates use the same typed query key API, so `utils.todos.list.setData` is fully typed.

## REST API Design: Concrete Patterns

### 1. Resource naming and URL structure

```
# Resources are nouns, actions are HTTP verbs
GET    /users              # list
POST   /users              # create
GET    /users/:id          # read
PATCH  /users/:id          # partial update  (not PUT unless replacing entirely)
DELETE /users/:id          # delete
GET    /users/:id/orders   # nested resource
POST   /users/:id/orders   # create child resource

# Avoid verbs in URLs:
BAD:  POST /users/createOrder
GOOD: POST /users/:id/orders

# Actions that don't fit CRUD — use sub-resources or ?action=
POST /users/:id/password-reset   # resource-oriented action
POST /orders/:id/cancellation    # better than DELETE with side effects
```

### 2. Versioning strategies

```typescript
// Strategy A: URL versioning (most visible, easiest to cache)
app.use('/v1', v1Router);
app.use('/v2', v2Router);

// Strategy B: Accept-Version header (cleaner URLs)
app.use((req, res, next) => {
  const version = req.headers['accept-version'] ?? '1';
  req.apiVersion = parseInt(version, 10);
  next();
});

// Strategy C: Content negotiation (most RESTful)
// Accept: application/vnd.myapi.v2+json
app.use((req, res, next) => {
  const match = req.headers.accept?.match(/vnd\.myapi\.v(\d+)\+json/);
  req.apiVersion = match ? parseInt(match[1]) : 1;
  next();
});
```

### 3. Cursor-based pagination

```typescript
import { z } from 'zod';

const PaginationQuery = z.object({
  cursor: z.string().optional(),   // opaque base64-encoded cursor
  limit:  z.coerce.number().int().min(1).max(100).default(20),
  sort:   z.enum(['created_asc', 'created_desc']).default('created_desc'),
});

router.get('/users', async (req, res) => {
  const { cursor, limit, sort } = PaginationQuery.parse(req.query);

  // Decode cursor: { id, createdAt } — must match sort field
  const decoded = cursor
    ? JSON.parse(Buffer.from(cursor, 'base64url').toString())
    : null;

  const [dir, field] = sort === 'created_desc' ? ['<', 'DESC'] : ['>', 'ASC'];
  const users = await db.query(
    `SELECT * FROM users
     WHERE ($1::timestamptz IS NULL OR created_at ${dir} $1)
     ORDER BY created_at ${field}, id ${field}
     LIMIT $2 + 1`,  // fetch one extra to determine if there's a next page
    [decoded?.createdAt ?? null, limit]
  );

  const hasNextPage = users.length > limit;
  const items = hasNextPage ? users.slice(0, limit) : users;
  const lastItem = items.at(-1);

  const nextCursor = hasNextPage && lastItem
    ? Buffer.from(JSON.stringify({ id: lastItem.id, createdAt: lastItem.createdAt })).toString('base64url')
    : null;

  res.json({
    data: items,
    pagination: { limit, nextCursor, hasNextPage },
    // HATEOAS links
    links: {
      self: `/users?limit=${limit}&sort=${sort}${cursor ? `&cursor=${cursor}` : ''}`,
      next: nextCursor ? `/users?limit=${limit}&sort=${sort}&cursor=${nextCursor}` : null,
    },
  });
});
```

### 4. HTTP status codes used correctly

```typescript
// 200 OK        — successful GET, PATCH, DELETE
// 201 Created   — successful POST that creates a resource
// 204 No Content — successful DELETE with no body
// 400 Bad Request — validation failed (include error details)
// 401 Unauthorized — not authenticated
// 403 Forbidden — authenticated but not authorized
// 404 Not Found — resource doesn't exist
// 409 Conflict — duplicate, optimistic lock failure
// 422 Unprocessable Entity — business rule violation
// 429 Too Many Requests — rate limited
// 503 Service Unavailable — downstream dependency down

router.post('/users', async (req, res) => {
  const result = CreateUserSchema.safeParse(req.body);
  if (!result.success) {
    return res.status(400).json({
      error: 'VALIDATION_ERROR',
      details: result.error.issues.map(i => ({ path: i.path.join('.'), message: i.message })),
    });
  }
  const existing = await db.users.findByEmail(result.data.email);
  if (existing) return res.status(409).json({ error: 'EMAIL_TAKEN' });

  const user = await db.users.create(result.data);
  res.status(201).location(`/users/${user.id}`).json({ data: user });
});
```

**Cursor pagination advantage over offset:** Offset pagination breaks when items are inserted/deleted between pages (items skip or repeat). Cursors are stable — they point to a specific record position, immune to concurrent modifications.

```typescript
import jwt from 'jsonwebtoken';
import { createClient } from 'redis';
import { randomUUID } from 'crypto';
import type { Request, Response, NextFunction } from 'express';

const redis = createClient({ url: process.env.REDIS_URL });
await redis.connect();

const ACCESS_SECRET  = process.env.ACCESS_TOKEN_SECRET!;   // 256-bit random
const REFRESH_SECRET = process.env.REFRESH_TOKEN_SECRET!;  // different secret
const ACCESS_TTL  = 15 * 60;          // 15 minutes (seconds)
const REFRESH_TTL = 7 * 24 * 60 * 60; // 7 days (seconds)

interface TokenPayload { sub: string; jti: string; iat: number; }

function signAccess(userId: string): string {
  return jwt.sign({ sub: userId, jti: randomUUID() }, ACCESS_SECRET, {
    expiresIn: ACCESS_TTL, algorithm: 'HS256',
  });
}

function signRefresh(userId: string): string {
  return jwt.sign({ sub: userId, jti: randomUUID() }, REFRESH_SECRET, {
    expiresIn: REFRESH_TTL, algorithm: 'HS256',
  });
}

const COOKIE_OPTS = {
  httpOnly: true,       // not accessible to JS — prevents XSS token theft
  secure:   true,       // HTTPS only
  sameSite: 'strict' as const,  // CSRF protection
  path:     '/',
};

// ---- Login ----
router.post('/auth/login', async (req, res) => {
  const { email, password } = req.body;
  const user = await db.users.verifyCredentials(email, password);
  if (!user) return res.status(401).json({ error: 'Invalid credentials' });

  const accessToken  = signAccess(user.id);
  const refreshToken = signRefresh(user.id);

  res
    .cookie('access_token',  accessToken,  { ...COOKIE_OPTS, maxAge: ACCESS_TTL  * 1000 })
    .cookie('refresh_token', refreshToken, { ...COOKIE_OPTS, maxAge: REFRESH_TTL * 1000, path: '/auth/refresh' })
    .json({ userId: user.id });  // never send tokens in JSON body
});

// ---- Token rotation on refresh ----
router.post('/auth/refresh', async (req, res) => {
  const token = req.cookies.refresh_token;
  if (!token) return res.status(401).json({ error: 'No refresh token' });

  let payload: TokenPayload;
  try {
    payload = jwt.verify(token, REFRESH_SECRET) as TokenPayload;
  } catch {
    return res.status(401).json({ error: 'Invalid refresh token' });
  }

  // Check revocation blocklist
  const isRevoked = await redis.exists(`revoked:${payload.jti}`);
  if (isRevoked) return res.status(401).json({ error: 'Token revoked' });

  // Rotate: revoke old refresh token immediately (prevent reuse)
  const ttlRemaining = payload.exp! - Math.floor(Date.now() / 1000);
  await redis.setEx(`revoked:${payload.jti}`, ttlRemaining, '1');

  const newAccess  = signAccess(payload.sub);
  const newRefresh = signRefresh(payload.sub);

  res
    .cookie('access_token',  newAccess,  { ...COOKIE_OPTS, maxAge: ACCESS_TTL  * 1000 })
    .cookie('refresh_token', newRefresh, { ...COOKIE_OPTS, maxAge: REFRESH_TTL * 1000, path: '/auth/refresh' })
    .json({ ok: true });
});

// ---- Logout ----
router.post('/auth/logout', async (req, res) => {
  const token = req.cookies.refresh_token;
  if (token) {
    try {
      const payload = jwt.decode(token) as TokenPayload;
      if (payload?.jti && payload?.exp) {
        const ttl = payload.exp - Math.floor(Date.now() / 1000);
        if (ttl > 0) await redis.setEx(`revoked:${payload.jti}`, ttl, '1');
      }
    } catch {} // best-effort revocation
  }
  res.clearCookie('access_token').clearCookie('refresh_token').json({ ok: true });
});

// ---- Auth middleware ----
export async function requireAuth(req: Request, res: Response, next: NextFunction) {
  const token = req.cookies.access_token;
  if (!token) return res.status(401).json({ error: 'Not authenticated' });

  try {
    const payload = jwt.verify(token, ACCESS_SECRET) as TokenPayload;
    const revoked = await redis.exists(`revoked:${payload.jti}`);
    if (revoked) return res.status(401).json({ error: 'Token revoked' });
    (req as any).userId = payload.sub;
    next();
  } catch (err) {
    if (err instanceof jwt.TokenExpiredError) {
      return res.status(401).json({ error: 'TOKEN_EXPIRED' }); // client should refresh
    }
    return res.status(401).json({ error: 'Invalid token' });
  }
}
```

**Security model:** Short-lived access tokens (15min) limit the blast radius if leaked. Refresh tokens are path-scoped (`/auth/refresh`) so they're only sent when needed. Token rotation means a stolen refresh token can only be used once — the second use triggers a revocation race. Redis TTL ensures the blocklist self-cleans.

```typescript
import { Request, Response, NextFunction } from 'express';
import { Pool } from 'pg';
import { execFile } from 'child_process';
import { promisify } from 'util';

const execFileAsync = promisify(execFile);
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// ============================================================
// PROTOTYPE POLLUTION PREVENTION
// ============================================================

// Vulnerable: merging user JSON into object allows __proto__ injection
// const config = {}; Object.assign(config, JSON.parse(userInput));
// Fix 1: JSON schema validation rejects unknown keys
// Fix 2: freeze prototype before app starts
Object.freeze(Object.prototype);

// Fix 3: create objects with no prototype for accumulator/cache patterns
function safeParseJSON(input: string): Record<string, unknown> | null {
  try {
    const parsed = JSON.parse(input);
    if (typeof parsed !== 'object' || Array.isArray(parsed) || parsed === null) return null;

    // Shallow copy into null-prototype object
    const safe = Object.create(null) as Record<string, unknown>;
    for (const key of Object.keys(parsed)) {
      if (key === '__proto__' || key === 'constructor' || key === 'prototype') continue;
      safe[key] = parsed[key];
    }
    return safe;
  } catch {
    return null;
  }
}

// Middleware: strip dangerous keys from req.body recursively
function deepSanitize(obj: unknown): unknown {
  if (typeof obj !== 'object' || obj === null) return obj;
  if (Array.isArray(obj)) return obj.map(deepSanitize);

  const safe: Record<string, unknown> = Object.create(null);
  for (const [key, val] of Object.entries(obj)) {
    if (['__proto__', 'constructor', 'prototype'].includes(key)) continue;
    safe[key] = deepSanitize(val);
  }
  return safe;
}

export function prototypePollutionGuard(req: Request, _: Response, next: NextFunction) {
  req.body   = deepSanitize(req.body);
  req.query  = deepSanitize(req.query) as any;
  req.params = deepSanitize(req.params) as any;
  next();
}

// ============================================================
// SQL INJECTION — parameterized queries
// ============================================================

// BAD — string interpolation
async function getUserBad(email: string) {
  // email = "' OR '1'='1" → returns all users
  return pool.query(`SELECT * FROM users WHERE email = '${email}'`);
}

// GOOD — parameterized query ($1 placeholder)
async function getUser(email: string) {
  const result = await pool.query(
    'SELECT id, name, email FROM users WHERE email = $1 LIMIT 1',
    [email]  // pg driver escapes this — never interpolated into SQL
  );
  return result.rows[0] ?? null;
}

// GOOD — dynamic ORDER BY (can't parameterize column names)
const ALLOWED_SORT_COLUMNS = new Set(['created_at', 'name', 'score'] as const);
type SortColumn = 'created_at' | 'name' | 'score';

async function getUsers(sortBy: string, limit: number) {
  // Allowlist — never trust user input for identifiers
  const column: SortColumn = ALLOWED_SORT_COLUMNS.has(sortBy as SortColumn)
    ? sortBy as SortColumn
    : 'created_at';
  const safeLimit = Math.min(Math.max(1, Math.floor(limit)), 100);

  return pool.query(
    `SELECT id, name FROM users ORDER BY ${column} DESC LIMIT $1`,
    [safeLimit]
  );
}

// ============================================================
// COMMAND INJECTION — execFile not exec
// ============================================================

// BAD — shell injection
// exec(`convert ${userFilename} output.png`)
// filename = 'img.jpg; rm -rf /' → disaster

// GOOD — execFile with args array (no shell, no injection)
async function convertImage(inputPath: string, outputPath: string) {
  // Validate paths before passing to subprocess
  const safePath = (p: string) => /^[\w./\-]+$/.test(p);
  if (!safePath(inputPath) || !safePath(outputPath)) {
    throw new Error('Invalid file path');
  }

  // execFile does NOT invoke a shell — args are passed directly to execv
  const { stdout } = await execFileAsync('convert', [
    inputPath,
    '-resize', '800x600',
    outputPath,
  ], { timeout: 30_000 });

  return stdout;
}
```

**Why `execFile` not `exec`:** `exec` passes the command to `/bin/sh`, enabling shell metacharacters (`; | & $( )`). `execFile` calls `execv` directly — the first argument is the binary, subsequent arguments are passed verbatim. Even `'; rm -rf /'` is treated as a literal string argument, not shell code.

```typescript
import { ApolloServer } from '@apollo/server';
import { startStandaloneServer } from '@apollo/server/standalone';
import DataLoader from 'dataloader';

// ---- Schema ----
const typeDefs = `#graphql
  type Author {
    id: ID!
    name: String!
    email: String!
    posts: [Post!]!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    author: Author!          # N+1 risk
    tags: [Tag!]!            # N+1 risk
    commentCount: Int!
  }

  type Tag {
    id: ID!
    name: String!
  }

  type Query {
    posts(limit: Int = 10, offset: Int = 0): [Post!]!
    post(id: ID!): Post
    author(id: ID!): Author
  }
`;

// ---- DataLoader factory (created per-request to avoid cross-request caching) ----
interface Context {
  loaders: {
    author:       DataLoader<string, Author>;
    tagsForPost:  DataLoader<string, Tag[]>;
    commentCount: DataLoader<string, number>;
  };
}

function createLoaders(): Context['loaders'] {
  return {
    // Batch: [userId1, userId2, userId3] → single SQL IN clause
    author: new DataLoader<string, Author>(async (ids) => {
      const authors = await db.query<Author>(
        'SELECT * FROM authors WHERE id = ANY($1)',
        [[...ids]]  // PostgreSQL ANY() with array
      );
      // DataLoader requires results in same order as input keys
      const map = new Map(authors.map(a => [a.id, a]));
      return ids.map(id => map.get(id) ?? new Error(`Author ${id} not found`));
    }),

    // Batch: [postId1, postId2] → single query with GROUP BY
    tagsForPost: new DataLoader<string, Tag[]>(async (postIds) => {
      const rows = await db.query<{ postId: string } & Tag>(
        `SELECT pt.post_id as "postId", t.id, t.name
         FROM post_tags pt JOIN tags t ON t.id = pt.tag_id
         WHERE pt.post_id = ANY($1)`,
        [[...postIds]]
      );
      const map = new Map<string, Tag[]>(postIds.map(id => [id, []]));
      for (const row of rows) map.get(row.postId)?.push({ id: row.id, name: row.name });
      return postIds.map(id => map.get(id) ?? []);
    }),

    commentCount: new DataLoader<string, number>(async (postIds) => {
      const rows = await db.query<{ postId: string; count: string }>(
        `SELECT post_id as "postId", COUNT(*) as count
         FROM comments WHERE post_id = ANY($1)
         GROUP BY post_id`,
        [[...postIds]]
      );
      const map = new Map(rows.map(r => [r.postId, parseInt(r.count)]));
      return postIds.map(id => map.get(id) ?? 0);
    }),
  };
}

// ---- Resolvers ----
const resolvers = {
  Query: {
    posts: (_: unknown, { limit, offset }: { limit: number; offset: number }) =>
      db.query('SELECT * FROM posts ORDER BY created_at DESC LIMIT $1 OFFSET $2', [limit, offset]),

    post: (_: unknown, { id }: { id: string }) =>
      db.query('SELECT * FROM posts WHERE id = $1', [id]).then(r => r[0] ?? null),

    author: (_: unknown, { id }: { id: string }, ctx: Context) =>
      ctx.loaders.author.load(id),
  },

  Post: {
    // Without DataLoader: 1 query per post → 10 posts = 11 queries
    // With DataLoader: batched into 1 query regardless of list size
    author: (post: Post, _: unknown, ctx: Context) =>
      ctx.loaders.author.load(post.authorId),

    tags: (post: Post, _: unknown, ctx: Context) =>
      ctx.loaders.tagsForPost.load(post.id),

    commentCount: (post: Post, _: unknown, ctx: Context) =>
      ctx.loaders.commentCount.load(post.id),
  },

  Author: {
    posts: (author: Author) =>
      db.query('SELECT * FROM posts WHERE author_id = $1', [author.id]),
  },
};

// ---- Server ----
const server = new ApolloServer<Context>({ typeDefs, resolvers });
await startStandaloneServer(server, {
  context: async () => ({ loaders: createLoaders() }),  // fresh loaders per request
});
```

**Why N+1 happens without DataLoader:**
```
Query: posts(10) → 1 DB call
  post.author      → 1 call × 10 = 10 calls   ← N+1
  post.tags        → 1 call × 10 = 10 calls   ← N+1
  post.commentCount→ 1 call × 10 = 10 calls   ← N+1
Total: 31 queries
```

**With DataLoader:** GraphQL field resolvers call `loader.load(id)`. DataLoader collects all `load()` calls made within the same event loop tick, then calls the batch function once with all IDs. Result: 4 queries total. Loaders are created per-request to prevent cache leaking between users.

## Feature Envy Explained

Feature envy occurs when a method in class A accesses data and behavior from class B more than from its own class. It signals that the method *belongs* in class B.

```typescript
// BEFORE: Order.calculateDiscount() envies Customer
class Customer {
  name: string;
  loyaltyYears: number;
  tier: 'bronze' | 'silver' | 'gold' | 'platinum';
  totalSpend: number;
  hasPremiumMembership: boolean;

  constructor(data: Omit<Customer, never>) { Object.assign(this, data); }
}

class Order {
  private items: OrderItem[];
  private customer: Customer;

  // SMELL: this method touches Customer fields 5× and Order fields 1×
  // It's doing Customer's job
  calculateDiscount(): number {
    let discount = 0;

    // Loyalty discount — pure Customer logic
    if (this.customer.loyaltyYears >= 5) discount += 0.05;
    if (this.customer.loyaltyYears >= 10) discount += 0.05;

    // Tier discount — pure Customer logic
    const tierDiscounts = { bronze: 0, silver: 0.03, gold: 0.07, platinum: 0.12 };
    discount += tierDiscounts[this.customer.tier];

    // Premium membership — pure Customer logic
    if (this.customer.hasPremiumMembership) discount += 0.05;

    // Volume spend — pure Customer logic
    if (this.customer.totalSpend > 10_000) discount += 0.02;

    return Math.min(discount, 0.25); // cap at 25%
  }

  total(): number {
    const subtotal = this.items.reduce((s, i) => s + i.price * i.qty, 0);
    return subtotal * (1 - this.calculateDiscount()); // actually uses Customer's discount
  }
}
```

## Refactored: Move logic to where the data lives

```typescript
// AFTER: Customer owns its discount logic, Order delegates

class Customer {
  constructor(
    public readonly name: string,
    public readonly loyaltyYears: number,
    public readonly tier: 'bronze' | 'silver' | 'gold' | 'platinum',
    public readonly totalSpend: number,
    public readonly hasPremiumMembership: boolean,
  ) {}

  // Moved here — this class owns ALL the data this needs
  discountRate(): number {
    const loyaltyBonus = this.loyaltyYears >= 10 ? 0.10
                       : this.loyaltyYears >= 5  ? 0.05 : 0;

    const tierDiscount: Record<Customer['tier'], number> = {
      bronze: 0, silver: 0.03, gold: 0.07, platinum: 0.12,
    };

    const membershipBonus = this.hasPremiumMembership ? 0.05 : 0;
    const spendBonus      = this.totalSpend > 10_000   ? 0.02 : 0;

    return Math.min(
      loyaltyBonus + tierDiscount[this.tier] + membershipBonus + spendBonus,
      0.25
    );
  }

  // Also good to add derived helpers on Customer
  isVip(): boolean {
    return this.tier === 'platinum' || this.loyaltyYears >= 10;
  }
}

class Order {
  constructor(
    private readonly items: OrderItem[],
    private readonly customer: Customer,
  ) {}

  subtotal(): number {
    return this.items.reduce((s, i) => s + i.price * i.qty, 0);
  }

  // Order now only touches its OWN data + delegates to Customer
  total(): number {
    return this.subtotal() * (1 - this.customer.discountRate());
  }

  // Order-specific logic stays here
  itemCount(): number {
    return this.items.reduce((s, i) => s + i.qty, 0);
  }
}

// Usage
const customer = new Customer('Jane', 8, 'gold', 15_000, true);
const order    = new Order(items, customer);

console.log(customer.discountRate()); // 0.21 — testable in isolation
console.log(order.total());           // Order delegates correctly

// Now you can write focused tests:
describe('Customer.discountRate', () => {
  it('caps at 25% even with all bonuses stacked', () => {
    const vip = new Customer('Bob', 15, 'platinum', 50_000, true);
    expect(vip.discountRate()).toBe(0.25);
  });
});
```

**Before/After summary:**
- `Order.calculateDiscount()` touched 5 Customer fields, 0 Order fields → moved to `Customer.discountRate()`
- `Order.total()` now only delegates: `subtotal() * (1 - customer.discountRate())`
- `Customer.discountRate()` is now independently testable without constructing an `Order`
- Changing discount logic requires editing only `Customer`, not hunting through `Order`

## Strategy Pattern: Payment Processing

### TypeScript

```typescript
// Strategy interface — defines the contract
interface PaymentStrategy {
  readonly name: string;
  charge(amount: number, currency: string, metadata: Record<string, string>): Promise<PaymentResult>;
  refund(transactionId: string, amount: number): Promise<void>;
}

interface PaymentResult { transactionId: string; fee: number; }

// Concrete strategies
class StripeStrategy implements PaymentStrategy {
  readonly name = 'stripe';
  constructor(private client: Stripe) {}

  async charge(amount: number, currency: string, meta: Record<string, string>): Promise<PaymentResult> {
    const intent = await this.client.paymentIntents.create({
      amount: Math.round(amount * 100), currency, metadata: meta,
    });
    return { transactionId: intent.id, fee: amount * 0.029 + 0.30 };
  }

  async refund(transactionId: string, amount: number) {
    await this.client.refunds.create({ payment_intent: transactionId, amount: Math.round(amount * 100) });
  }
}

class PayPalStrategy implements PaymentStrategy {
  readonly name = 'paypal';
  constructor(private client: PayPalClient) {}

  async charge(amount: number, currency: string, meta: Record<string, string>): Promise<PaymentResult> {
    const order = await this.client.orders.create({
      intent: 'CAPTURE',
      purchase_units: [{ amount: { currency_code: currency, value: amount.toFixed(2) } }],
    });
    return { transactionId: order.id, fee: amount * 0.034 + 0.49 };
  }

  async refund(transactionId: string, amount: number) {
    await this.client.captures.refund(transactionId, { amount: { value: amount.toFixed(2) } });
  }
}

// Context — owns the strategy, exposes uniform API
class PaymentProcessor {
  private strategy: PaymentStrategy;

  constructor(strategy: PaymentStrategy) { this.strategy = strategy; }

  // Switch strategy at runtime (e.g., based on user preference or A/B test)
  setStrategy(strategy: PaymentStrategy) { this.strategy = strategy; }

  async processPayment(amount: number, currency: string, userId: string): Promise<PaymentResult> {
    console.log(`Processing via ${this.strategy.name}`);
    return this.strategy.charge(amount, currency, { userId });
  }
}

// Usage
const processor = new PaymentProcessor(new StripeStrategy(stripeClient));
const result = await processor.processPayment(99.99, 'USD', 'user-123');

// Switch to PayPal for EU users
if (user.region === 'EU') processor.setStrategy(new PayPalStrategy(paypalClient));
```

### Go

```go
// Go uses interfaces implicitly — no 'implements' keyword
package payment

import "context"

type PaymentResult struct {
    TransactionID string
    Fee           float64
}

// Strategy interface — satisfied implicitly
type Strategy interface {
    Name() string
    Charge(ctx context.Context, amount float64, currency, userID string) (PaymentResult, error)
    Refund(ctx context.Context, txID string, amount float64) error
}

// Concrete strategy
type StripeStrategy struct { client *stripe.Client }

func (s *StripeStrategy) Name() string { return "stripe" }

func (s *StripeStrategy) Charge(ctx context.Context, amount float64, currency, userID string) (PaymentResult, error) {
    params := &stripe.PaymentIntentParams{
        Amount:   stripe.Int64(int64(amount * 100)),
        Currency: stripe.String(currency),
    }
    pi, err := s.client.PaymentIntents.New(params)
    if err != nil { return PaymentResult{}, fmt.Errorf("stripe charge: %w", err) }
    return PaymentResult{TransactionID: pi.ID, Fee: amount*0.029 + 0.30}, nil
}

func (s *StripeStrategy) Refund(ctx context.Context, txID string, amount float64) error {
    _, err := s.client.Refunds.New(&stripe.RefundParams{PaymentIntent: &txID})
    return err
}

// Context
type Processor struct { strategy Strategy }

func NewProcessor(s Strategy) *Processor { return &Processor{strategy: s} }
func (p *Processor) SetStrategy(s Strategy) { p.strategy = s }

func (p *Processor) ProcessPayment(ctx context.Context, amount float64, currency, userID string) (PaymentResult, error) {
    return p.strategy.Charge(ctx, amount, currency, userID)
}
```

### Trade-offs

| Aspect | TypeScript | Go |
|--------|-----------|----|
| Interface satisfaction | Explicit `implements` (caught at declaration) | Implicit (structural typing — any type satisfying the interface works, no declaration needed) |
| Runtime strategy swap | `setStrategy(new PayPalStrategy(...))` | `p.SetStrategy(&PayPalStrategy{...})` — identical ergonomics |
| Testing | Easy to mock: `const mock: PaymentStrategy = { charge: vi.fn(), ... }` | Use interface: `var _ Strategy = &MockStrategy{}` compile-time check |
| Functional alternative | Can use plain functions / closures instead of classes | Function types (`type ChargeFn func(...)`) work but lose grouping |
| Null safety | TS: strategy could be undefined without `!` assertion | Go: nil interface panics — initialize in constructor |

Go's implicit interfaces are particularly powerful here: you can make a third-party payment client satisfy `Strategy` without modifying it, just by writing an adapter that calls its methods.

## Observer Pattern: Stock Price Feed

### TypeScript

```typescript
type EventMap = {
  priceChange: { symbol: string; oldPrice: number; newPrice: number; timestamp: Date };
  marketOpen:  { time: Date };
  marketClose: { time: Date };
};

type Handler<T> = (event: T) => void | Promise<void>;

class TypedEventEmitter<Events extends Record<string, unknown>> {
  private handlers = new Map<keyof Events, Set<Handler<any>>>();

  on<K extends keyof Events>(event: K, handler: Handler<Events[K]>): () => void {
    if (!this.handlers.has(event)) this.handlers.set(event, new Set());
    this.handlers.get(event)!.add(handler);
    // Return unsubscribe function
    return () => this.handlers.get(event)?.delete(handler);
  }

  once<K extends keyof Events>(event: K, handler: Handler<Events[K]>): () => void {
    const wrapper: Handler<Events[K]> = (e) => { unsub(); return handler(e); };
    const unsub = this.on(event, wrapper);
    return unsub;
  }

  async emit<K extends keyof Events>(event: K, data: Events[K]): Promise<void> {
    const fns = this.handlers.get(event);
    if (!fns) return;
    await Promise.allSettled([...fns].map(fn => fn(data)));
  }

  removeAll<K extends keyof Events>(event?: K) {
    if (event) this.handlers.delete(event);
    else this.handlers.clear();
  }
}

// Subject
class StockFeed extends TypedEventEmitter<EventMap> {
  private prices = new Map<string, number>();

  updatePrice(symbol: string, newPrice: number) {
    const oldPrice = this.prices.get(symbol) ?? newPrice;
    this.prices.set(symbol, newPrice);
    if (oldPrice !== newPrice) {
      this.emit('priceChange', { symbol, oldPrice, newPrice, timestamp: new Date() });
    }
  }
}

// Observers
const feed = new StockFeed();

// Logger observer
const unsubLogger = feed.on('priceChange', ({ symbol, oldPrice, newPrice }) => {
  const pct = (((newPrice - oldPrice) / oldPrice) * 100).toFixed(2);
  console.log(`[${symbol}] ${oldPrice} → ${newPrice} (${pct}%)`);
});

// Alert observer — async
const unsubAlerts = feed.on('priceChange', async ({ symbol, newPrice, oldPrice }) => {
  const drop = (oldPrice - newPrice) / oldPrice;
  if (drop > 0.05) {
    await alertService.send(`ALERT: ${symbol} dropped ${(drop * 100).toFixed(1)}%`);
  }
});

// UI updater
const unsubUI = feed.on('priceChange', ({ symbol, newPrice }) => {
  uiStore.update(symbol, newPrice);
});

// Simulate price changes
feed.updatePrice('AAPL', 185.50);
feed.updatePrice('AAPL', 175.00); // >5% drop — triggers alert

// Cleanup (e.g., on component unmount)
unsubLogger();
unsubAlerts();
unsubUI();
```

### Python

```python
from __future__ import annotations
from dataclasses import dataclass
from datetime import datetime
from typing import Callable, TypeVar, Generic
from collections import defaultdict
import asyncio

@dataclass(frozen=True)
class PriceChangeEvent:
    symbol: str
    old_price: float
    new_price: float
    timestamp: datetime

    @property
    def pct_change(self) -> float:
        return (self.new_price - self.old_price) / self.old_price * 100

E = TypeVar('E')

class EventEmitter(Generic[E]):
    def __init__(self):
        self._handlers: list[Callable[[E], None]] = []

    def subscribe(self, handler: Callable[[E], None]) -> Callable[[], None]:
        self._handlers.append(handler)
        def unsubscribe():
            self._handlers.remove(handler)
        return unsubscribe

    def emit(self, event: E) -> None:
        for handler in list(self._handlers):  # copy to allow removal during iteration
            handler(event)

class StockFeed:
    def __init__(self):
        self.price_changed: EventEmitter[PriceChangeEvent] = EventEmitter()
        self._prices: dict[str, float] = {}

    def update_price(self, symbol: str, price: float) -> None:
        old = self._prices.get(symbol, price)
        self._prices[symbol] = price
        if old != price:
            self.price_changed.emit(
                PriceChangeEvent(symbol, old, price, datetime.utcnow())
            )

# Observers as plain functions (simpler than classes in Python)
def make_logger() -> Callable[[PriceChangeEvent], None]:
    def handler(e: PriceChangeEvent) -> None:
        sign = '+' if e.pct_change >= 0 else ''
        print(f'[{e.symbol}] {e.old_price:.2f} → {e.new_price:.2f} ({sign}{e.pct_change:.2f}%)')
    return handler

def make_alert(threshold: float = 0.05) -> Callable[[PriceChangeEvent], None]:
    def handler(e: PriceChangeEvent) -> None:
        if e.old_price > 0 and (e.old_price - e.new_price) / e.old_price > threshold:
            print(f'ALERT: {e.symbol} dropped {abs(e.pct_change):.1f}%!')
    return handler

# Usage
feed = StockFeed()
unsub_log   = feed.price_changed.subscribe(make_logger())
unsub_alert = feed.price_changed.subscribe(make_alert(threshold=0.05))

feed.update_price('AAPL', 185.50)
feed.update_price('AAPL', 175.00)  # triggers alert

unsub_log()    # clean up
unsub_alert()
```

**Language comparison:**
- TypeScript: type parameters on event maps give compile-time guarantees that handlers receive the right event type
- Python: `dataclass(frozen=True)` makes events immutable — handlers can't corrupt shared state
- Both return unsubscribe callables — no need for Observer classes with `update()` methods
- Python's duck typing means any callable works as an observer; TypeScript requires matching the `Handler<T>` signature

## Factory Patterns: UI Widget Theming

### TypeScript — Abstract Factory

```typescript
// Product interfaces
interface Button    { render(): string; onClick(handler: () => void): void; }
interface TextInput { render(): string; getValue(): string; }

// Abstract factory
interface UIFactory {
  createButton(label: string): Button;
  createTextInput(placeholder: string): TextInput;
}

// Web theme
class WebButton implements Button {
  private handlers: (() => void)[] = [];
  constructor(private label: string) {}
  render() { return `<button class="btn-primary">${this.label}</button>`; }
  onClick(h: () => void) { this.handlers.push(h); }
}

class WebTextInput implements TextInput {
  private value = '';
  constructor(private placeholder: string) {}
  render() { return `<input type="text" placeholder="${this.placeholder}" />`; }
  getValue() { return this.value; }
}

class WebUIFactory implements UIFactory {
  createButton(label: string)          { return new WebButton(label); }
  createTextInput(placeholder: string) { return new WebTextInput(placeholder); }
}

// Terminal theme
class TerminalButton implements Button {
  constructor(private label: string) {}
  render() { return `[ ${this.label} ]`; }
  onClick(h: () => void) { process.stdin.once('data', h); }
}

class TerminalTextInput implements TextInput {
  private value = '';
  constructor(private placeholder: string) {}
  render() { return `> _  (${this.placeholder})`; }
  getValue() { return this.value; }
}

class TerminalUIFactory implements UIFactory {
  createButton(label: string)          { return new TerminalButton(label); }
  createTextInput(placeholder: string) { return new TerminalTextInput(placeholder); }
}

// Application — depends only on the factory interface
function renderLoginForm(factory: UIFactory) {
  const emailInput = factory.createTextInput('Enter email');
  const passInput  = factory.createTextInput('Enter password');
  const submitBtn  = factory.createButton('Log In');

  submitBtn.onClick(() => console.log('Logging in:', emailInput.getValue()));

  return [emailInput.render(), passInput.render(), submitBtn.render()].join('\n');
}

// Switch themes without changing application code
const env     = process.env.UI_MODE ?? 'web';
const factory = env === 'terminal' ? new TerminalUIFactory() : new WebUIFactory();
console.log(renderLoginForm(factory));
```

### Rust — Trait Objects (Factory Method style)

```rust
// Traits define the products
pub trait Button {
    fn render(&self) -> String;
    fn label(&self) -> &str;
}

pub trait TextInput {
    fn render(&self) -> String;
    fn placeholder(&self) -> &str;
}

// Factory Method trait — subclasses decide which concrete type to create
pub trait UIFactory {
    type Btn: Button;    // Associated types = zero-cost vs trait objects
    type Input: TextInput;

    fn create_button(&self, label: &str) -> Self::Btn;
    fn create_text_input(&self, placeholder: &str) -> Self::Input;
}

// Web implementations
pub struct WebButton    { label: String }
pub struct WebTextInput { placeholder: String }

impl Button    for WebButton    { fn render(&self) -> String { format!("<button>{}</button>", self.label) } fn label(&self) -> &str { &self.label } }
impl TextInput for WebTextInput { fn render(&self) -> String { format!("<input placeholder=\"{}\" />", self.placeholder) } fn placeholder(&self) -> &str { &self.placeholder } }

pub struct WebUIFactory;
impl UIFactory for WebUIFactory {
    type Btn   = WebButton;
    type Input = WebTextInput;
    fn create_button(&self, label: &str)          -> WebButton    { WebButton { label: label.to_string() } }
    fn create_text_input(&self, placeholder: &str) -> WebTextInput { WebTextInput { placeholder: placeholder.to_string() } }
}

// Dynamic dispatch version (when factory type not known at compile time)
pub fn render_form_dynamic(
    factory: &dyn Fn(&str) -> Box<dyn Button>,
    labels: &[&str],
) -> Vec<String> {
    labels.iter().map(|&l| factory(l).render()).collect()
}

// Generic version (monomorphized — zero overhead)
fn render_login_form<F: UIFactory>(factory: &F) -> Vec<String> {
    vec![
        factory.create_text_input("Email").render(),
        factory.create_text_input("Password").render(),
        factory.create_button("Log In").render(),
    ]
}
```

### When to use each

**Factory Method:** One product, subclass decides which concrete type. Use when:
- A framework defines a process but lets subclasses plug in the product type
- You have one product family and mainly need extensibility via inheritance (TS) or associated types (Rust)

**Abstract Factory:** Multiple related products that must be consistent with each other. Use when:
- You need to enforce that `Button` and `TextInput` always come from the same theme
- Swapping an entire product family at runtime (theme switching, platform targeting)

In Rust: prefer associated types (`type Btn`) for zero-cost static dispatch; use `Box<dyn Button>` only when the concrete type isn't known at compile time.

## Adapter Pattern: Legacy Payment Gateway

### TypeScript

```typescript
// Modern interface (target)
interface PaymentGateway {
  charge(req: ChargeRequest): Promise<ChargeResponse>;
  refund(transactionId: string, amount: number): Promise<void>;
}

interface ChargeRequest  { amount: number; currency: string; cardToken: string; metadata?: Record<string, string>; }
interface ChargeResponse { transactionId: string; status: 'approved' | 'declined'; fee: number; }

// Legacy XML gateway (adaptee — cannot modify)
class LegacyXMLGateway {
  processPayment(xmlPayload: string): string { /* returns XML */ return ''; }
  voidTransaction(xmlRef: string): string    { return ''; }
}

// XML serialization helpers
function buildChargeXML(req: ChargeRequest): string {
  return `
    <PaymentRequest>
      <Amount>${(req.amount * 100).toFixed(0)}</Amount>
      <Currency>${req.currency.toUpperCase()}</Currency>
      <CardToken>${escapeXml(req.cardToken)}</CardToken>
      <Metadata>${Object.entries(req.metadata ?? {}).map(([k, v]) => `<${k}>${escapeXml(v)}</${k}>`).join('')}</Metadata>
    </PaymentRequest>
  `.trim();
}

function parseChargeXML(xml: string): ChargeResponse {
  // Simplified XML parsing — use a real parser in production
  const txId   = xml.match(/<TransactionId>([^<]+)<\/TransactionId>/)?.[1];
  const status = xml.match(/<Status>([^<]+)<\/Status>/)?.[1];
  const fee    = xml.match(/<ProcessingFee>(\d+)<\/ProcessingFee>/)?.[1];

  if (!txId || !status) throw new AdapterError('Invalid XML response', xml);

  return {
    transactionId: txId,
    status: status === 'APPROVED' ? 'approved' : 'declined',
    fee: fee ? parseInt(fee) / 100 : 0,
  };
}

// Error mapping
class AdapterError extends Error {
  constructor(message: string, public readonly rawResponse: string) {
    super(message);
    this.name = 'AdapterError';
  }
}

function mapLegacyError(xml: string): never {
  const code = xml.match(/<ErrorCode>(\d+)<\/ErrorCode>/)?.[1];
  switch (code) {
    case '4001': throw Object.assign(new Error('Card declined'), { code: 'CARD_DECLINED' });
    case '4002': throw Object.assign(new Error('Insufficient funds'), { code: 'INSUFFICIENT_FUNDS' });
    case '5001': throw Object.assign(new Error('Gateway timeout'), { code: 'GATEWAY_TIMEOUT' });
    default:     throw new AdapterError(`Unknown legacy error code: ${code}`, xml);
  }
}

// Adapter — wraps legacy, implements modern interface
class XMLPaymentAdapter implements PaymentGateway {
  constructor(private legacy: LegacyXMLGateway) {}

  async charge(req: ChargeRequest): Promise<ChargeResponse> {
    const xml      = buildChargeXML(req);
    const response = await Promise.resolve(this.legacy.processPayment(xml)); // legacy is sync

    if (response.includes('<Error>')) mapLegacyError(response);
    return parseChargeXML(response);
  }

  async refund(transactionId: string, amount: number): Promise<void> {
    const xml = `<VoidRequest><TransactionId>${transactionId}</TransactionId><Amount>${(amount * 100).toFixed(0)}</Amount></VoidRequest>`;
    const response = this.legacy.voidTransaction(xml);
    if (response.includes('<Error>')) mapLegacyError(response);
  }
}

// TypeScript structural typing note:
// Any object with { charge, refund } satisfying the signatures ALREADY implements PaymentGateway
// No 'implements' declaration needed — but explicit declaration catches mistakes at definition site
const gateway: PaymentGateway = new XMLPaymentAdapter(new LegacyXMLGateway());
await gateway.charge({ amount: 99.99, currency: 'USD', cardToken: 'tok_123' });
```

### Go

```go
package payment

import (
    "encoding/xml"
    "fmt"
)

// Modern target interface
type ChargeRequest  struct { Amount float64; Currency, CardToken string }
type ChargeResponse struct { TransactionID string; Status string; Fee float64 }

type Gateway interface {
    Charge(req ChargeRequest) (ChargeResponse, error)
    Refund(transactionID string, amount float64) error
}

// Adaptee (legacy)
type LegacyXMLGateway struct { endpoint string }
func (g *LegacyXMLGateway) ProcessPayment(xmlPayload string) (string, error) { return "", nil }
func (g *LegacyXMLGateway) VoidTransaction(xmlRef string) (string, error)    { return "", nil }

// XML structs
type xmlChargeRequest struct {
    XMLName  xml.Name `xml:"PaymentRequest"`
    Amount   int64    `xml:"Amount"`
    Currency string   `xml:"Currency"`
    Token    string   `xml:"CardToken"`
}

type xmlChargeResponse struct {
    XMLName       xml.Name `xml:"PaymentResponse"`
    TransactionID string   `xml:"TransactionId"`
    Status        string   `xml:"Status"`
    Fee           int64    `xml:"ProcessingFee"`
    ErrorCode     string   `xml:"ErrorCode,omitempty"`
    ErrorMessage  string   `xml:"ErrorMessage,omitempty"`
}

// Adapter
type XMLAdapter struct { legacy *LegacyXMLGateway }

func NewXMLAdapter(legacy *LegacyXMLGateway) Gateway {
    return &XMLAdapter{legacy: legacy}  // Go checks interface satisfaction here
}

func (a *XMLAdapter) Charge(req ChargeRequest) (ChargeResponse, error) {
    xmlReq, err := xml.Marshal(xmlChargeRequest{
        Amount: int64(req.Amount * 100), Currency: req.Currency, Token: req.CardToken,
    })
    if err != nil { return ChargeResponse{}, fmt.Errorf("marshal request: %w", err) }

    rawResp, err := a.legacy.ProcessPayment(string(xmlReq))
    if err != nil { return ChargeResponse{}, fmt.Errorf("legacy gateway: %w", err) }

    var resp xmlChargeResponse
    if err := xml.Unmarshal([]byte(rawResp), &resp); err != nil {
        return ChargeResponse{}, fmt.Errorf("unmarshal response: %w", err)
    }

    if resp.ErrorCode != "" { return ChargeResponse{}, mapLegacyError(resp.ErrorCode, resp.ErrorMessage) }

    return ChargeResponse{
        TransactionID: resp.TransactionID,
        Status:        mapStatus(resp.Status),
        Fee:           float64(resp.Fee) / 100,
    }, nil
}

func (a *XMLAdapter) Refund(txID string, amount float64) error {
    _, err := a.legacy.VoidTransaction(fmt.Sprintf(
        `<VoidRequest><TransactionId>%s</TransactionId><Amount>%d</Amount></VoidRequest>`,
        txID, int64(amount*100),
    ))
    return err
}

func mapLegacyError(code, msg string) error {
    switch code {
    case "4001": return fmt.Errorf("card declined: %s", msg)
    case "4002": return fmt.Errorf("insufficient funds")
    default:     return fmt.Errorf("gateway error %s: %s", code, msg)
    }
}

func mapStatus(s string) string {
    if s == "APPROVED" { return "approved" }
    return "declined"
}
```

**Structural vs nominal typing:**
- TypeScript: `XMLPaymentAdapter` satisfies `PaymentGateway` based purely on its method signatures — the `implements` keyword is optional documentation/safety
- Go: implicit structural typing means any struct with matching methods satisfies `Gateway` — the interface check happens at `NewXMLAdapter`'s return type, not at the struct definition
- Both languages: you can write adapters for third-party types without modifying them (unlike Java where you'd need a wrapper class and explicit `implements`)

```typescript
// ============================================================
// COMMANDS — write side (intent to change state)
// ============================================================
type CreatePostCommand = { type: 'CreatePost'; id: string; title: string; content: string; authorId: string; };
type PublishPostCommand = { type: 'PublishPost'; postId: string; publishedAt: Date; };
type UpdateTitleCommand = { type: 'UpdateTitle'; postId: string; newTitle: string; };
type Command = CreatePostCommand | PublishPostCommand | UpdateTitleCommand;

// Write model — rich domain object optimized for invariants
class Post {
  private constructor(
    public readonly id: string,
    public title: string,
    public content: string,
    public readonly authorId: string,
    public status: 'draft' | 'published',
    public publishedAt: Date | null,
  ) {}

  static create(id: string, title: string, content: string, authorId: string): Post {
    if (!title.trim()) throw new Error('Title required');
    return new Post(id, title, content, authorId, 'draft', null);
  }

  publish(at: Date) {
    if (this.status === 'published') throw new Error('Already published');
    this.status = 'published';
    this.publishedAt = at;
  }

  updateTitle(title: string) {
    if (!title.trim()) throw new Error('Title required');
    this.title = title;
  }
}

// Write repository
interface PostWriteRepository {
  load(id: string): Promise<Post | null>;
  save(post: Post): Promise<void>;
}

// ============================================================
// COMMAND HANDLERS
// ============================================================
type CommandHandler<C extends Command> = (cmd: C) => Promise<void>;

class PostCommandHandlers {
  constructor(
    private repo: PostWriteRepository,
    private events: EventBus,
  ) {}

  async handle(cmd: Command): Promise<void> {
    switch (cmd.type) {
      case 'CreatePost':   return this.createPost(cmd);
      case 'PublishPost':  return this.publishPost(cmd);
      case 'UpdateTitle':  return this.updateTitle(cmd);
    }
  }

  private async createPost(cmd: CreatePostCommand) {
    const post = Post.create(cmd.id, cmd.title, cmd.content, cmd.authorId);
    await this.repo.save(post);
    await this.events.emit({ type: 'PostCreated', postId: cmd.id, title: cmd.title, authorId: cmd.authorId, timestamp: new Date() });
  }

  private async publishPost(cmd: PublishPostCommand) {
    const post = await this.repo.load(cmd.postId);
    if (!post) throw new Error(`Post ${cmd.postId} not found`);
    post.publish(cmd.publishedAt);
    await this.repo.save(post);
    await this.events.emit({ type: 'PostPublished', postId: cmd.postId, publishedAt: cmd.publishedAt, timestamp: new Date() });
  }

  private async updateTitle(cmd: UpdateTitleCommand) {
    const post = await this.repo.load(cmd.postId);
    if (!post) throw new Error(`Post ${cmd.postId} not found`);
    post.updateTitle(cmd.newTitle);
    await this.repo.save(post);
    await this.events.emit({ type: 'PostTitleUpdated', postId: cmd.postId, newTitle: cmd.newTitle, timestamp: new Date() });
  }
}

// ============================================================
// READ MODELS — optimized for query patterns (denormalized)
// ============================================================
interface PostSummary {
  id: string; title: string; authorName: string;
  status: string; publishedAt: string | null; commentCount: number;
}

interface PostDetail extends PostSummary {
  content: string; wordCount: number; tags: string[];
}

// Read repository — separate from write, can be materialized views or ElasticSearch
interface PostReadRepository {
  findSummaries(filter: { status?: string; authorId?: string }, limit: number, cursor?: string): Promise<{ items: PostSummary[]; nextCursor: string | null }>;
  findById(id: string): Promise<PostDetail | null>;
  // Write side of read model
  upsert(post: Partial<PostDetail> & { id: string }): Promise<void>;
  incrementCommentCount(postId: string): Promise<void>;
}

// ============================================================
// QUERY HANDLERS
// ============================================================
type ListPostsQuery  = { type: 'ListPosts';  status?: string; authorId?: string; limit: number; cursor?: string; };
type GetPostQuery    = { type: 'GetPost';    postId: string; };
type Query = ListPostsQuery | GetPostQuery;

class PostQueryHandlers {
  constructor(private readRepo: PostReadRepository) {}

  async handle(query: Query): Promise<unknown> {
    switch (query.type) {
      case 'ListPosts': return this.readRepo.findSummaries(
        { status: query.status, authorId: query.authorId },
        query.limit, query.cursor
      );
      case 'GetPost':   return this.readRepo.findById(query.postId);
    }
  }
}

// ============================================================
// READ MODEL PROJECTOR — keeps read side in sync with events
// ============================================================
class PostProjector {
  constructor(
    private readRepo: PostReadRepository,
    private userRepo: { getName(id: string): Promise<string> },
  ) {}

  async on(event: DomainEvent): Promise<void> {
    switch (event.type) {
      case 'PostCreated': {
        const authorName = await this.userRepo.getName(event.authorId);
        await this.readRepo.upsert({
          id: event.postId, title: event.title, authorName,
          status: 'draft', publishedAt: null, commentCount: 0,
          content: '', wordCount: 0, tags: [],
        });
        break;
      }
      case 'PostPublished':
        await this.readRepo.upsert({ id: event.postId, status: 'published', publishedAt: event.publishedAt.toISOString() });
        break;
      case 'PostTitleUpdated':
        await this.readRepo.upsert({ id: event.postId, title: event.newTitle });
        break;
      case 'CommentAdded':
        await this.readRepo.incrementCommentCount(event.postId);
        break;
    }
  }
}

// ============================================================
// HTTP API layer wires commands and queries together
// ============================================================
router.post('/posts', async (req, res) => {
  await commandHandlers.handle({ type: 'CreatePost', id: randomUUID(), ...req.body });
  res.status(202).json({ accepted: true }); // 202 because side effects are async
});

router.get('/posts', async (req, res) => {
  const result = await queryHandlers.handle({ type: 'ListPosts', limit: 20, ...req.query });
  res.json(result);
});
```

**CQRS trade-offs:** The read model can be a fully denormalized SQL view, Redis cache, or Elasticsearch index — chosen purely for query performance, not write constraints. The trade-off is **eventual consistency**: after a command, there's a brief window where queries return stale data. For UIs, optimistic updates on the command result bridge this gap.

```typescript
// ============================================================
// DOMAIN EVENTS — immutable facts that happened
// ============================================================
type AccountOpened  = { type: 'AccountOpened';  id: string; owner: string; initialBalance: number; timestamp: Date; version: 1; };
type MoneyDeposited = { type: 'MoneyDeposited'; id: string; amount: number; reference: string; timestamp: Date; version: number; };
type MoneyWithdrawn = { type: 'MoneyWithdrawn'; id: string; amount: number; reference: string; timestamp: Date; version: number; };
type AccountClosed  = { type: 'AccountClosed';  id: string; timestamp: Date; version: number; };

type AccountEvent = AccountOpened | MoneyDeposited | MoneyWithdrawn | AccountClosed;

// ============================================================
// AGGREGATE — rebuilds from events
// ============================================================
interface AccountSnapshot { version: number; balance: number; owner: string; status: 'open' | 'closed'; }

class Account {
  private pendingEvents: AccountEvent[] = [];

  private constructor(
    public readonly id: string,
    public balance: number,
    public owner: string,
    public status: 'open' | 'closed',
    public version: number,
  ) {}

  // Rebuild from event stream
  static fromEvents(events: AccountEvent[], snapshot?: AccountSnapshot): Account {
    let acc: Account;
    let startVersion = 0;

    if (snapshot) {
      acc = new Account('', snapshot.balance, snapshot.owner, snapshot.status, snapshot.version);
      startVersion = snapshot.version;
    } else {
      if (events[0]?.type !== 'AccountOpened') throw new Error('First event must be AccountOpened');
      const e = events[0] as AccountOpened;
      acc = new Account(e.id, e.initialBalance, e.owner, 'open', 1);
      events = events.slice(1);
    }

    for (const event of events) {
      if (event.version <= startVersion) continue;
      acc.apply(event);
    }
    return acc;
  }

  // ---- Command methods (validate then record event) ----
  static open(id: string, owner: string, initialBalance: number): Account {
    if (initialBalance < 0) throw new Error('Initial balance cannot be negative');
    const acc = new Account(id, 0, '', 'open', 0);
    acc.record({ type: 'AccountOpened', id, owner, initialBalance, timestamp: new Date(), version: 1 });
    return acc;
  }

  deposit(amount: number, reference: string) {
    if (this.status === 'closed') throw new Error('Account is closed');
    if (amount <= 0) throw new Error('Deposit amount must be positive');
    this.record({ type: 'MoneyDeposited', id: this.id, amount, reference, timestamp: new Date(), version: this.version + 1 });
  }

  withdraw(amount: number, reference: string) {
    if (this.status === 'closed') throw new Error('Account is closed');
    if (amount <= 0) throw new Error('Withdrawal amount must be positive');
    if (amount > this.balance) throw new Error(`Insufficient funds: balance ${this.balance}, requested ${amount}`);
    this.record({ type: 'MoneyWithdrawn', id: this.id, amount, reference, timestamp: new Date(), version: this.version + 1 });
  }

  close() {
    if (this.status === 'closed') throw new Error('Already closed');
    if (this.balance > 0) throw new Error('Cannot close account with remaining balance');
    this.record({ type: 'AccountClosed', id: this.id, timestamp: new Date(), version: this.version + 1 });
  }

  // ---- Internal: apply event to state ----
  private apply(event: AccountEvent) {
    switch (event.type) {
      case 'AccountOpened':  this.balance = event.initialBalance; this.owner = event.owner; this.status = 'open'; break;
      case 'MoneyDeposited': this.balance += event.amount; break;
      case 'MoneyWithdrawn': this.balance -= event.amount; break;
      case 'AccountClosed':  this.status = 'closed'; break;
    }
    this.version = event.version;
  }

  private record(event: AccountEvent) {
    this.apply(event);
    this.pendingEvents.push(event);
  }

  flushPendingEvents(): AccountEvent[] {
    const events = this.pendingEvents;
    this.pendingEvents = [];
    return events;
  }

  toSnapshot(): AccountSnapshot {
    return { version: this.version, balance: this.balance, owner: this.owner, status: this.status };
  }
}

// ============================================================
// EVENT STORE
// ============================================================
interface EventStore {
  append(streamId: string, events: AccountEvent[], expectedVersion: number): Promise<void>;
  load(streamId: string, fromVersion?: number): Promise<AccountEvent[]>;
  loadSnapshot(streamId: string): Promise<AccountSnapshot | null>;
  saveSnapshot(streamId: string, snapshot: AccountSnapshot): Promise<void>;
}

// ============================================================
// REPOSITORY using event store
// ============================================================
const SNAPSHOT_EVERY = 50; // take snapshot every 50 events

class AccountRepository {
  constructor(private store: EventStore) {}

  async load(id: string): Promise<Account> {
    const snapshot = await this.store.loadSnapshot(id);
    const fromVersion = snapshot?.version ?? 0;
    const events = await this.store.load(id, fromVersion);

    if (!snapshot && events.length === 0) throw new Error(`Account ${id} not found`);
    return Account.fromEvents(events, snapshot ?? undefined);
  }

  async save(account: Account): Promise<void> {
    const events = account.flushPendingEvents();
    if (events.length === 0) return;

    const prevVersion = account.version - events.length;
    await this.store.append(account.id, events, prevVersion); // optimistic concurrency check

    // Snapshot when version crosses threshold
    if (Math.floor(account.version / SNAPSHOT_EVERY) > Math.floor(prevVersion / SNAPSHOT_EVERY)) {
      await this.store.saveSnapshot(account.id, account.toSnapshot());
    }
  }
}

// ============================================================
// PROJECTION — builds read model from event stream
// ============================================================
class BalanceLedgerProjection {
  private ledger = new Map<string, { owner: string; balance: number; txCount: number }>();

  project(event: AccountEvent) {
    switch (event.type) {
      case 'AccountOpened':
        this.ledger.set(event.id, { owner: event.owner, balance: event.initialBalance, txCount: 0 });
        break;
      case 'MoneyDeposited': {
        const acc = this.ledger.get(event.id)!;
        this.ledger.set(event.id, { ...acc, balance: acc.balance + event.amount, txCount: acc.txCount + 1 });
        break;
      }
      case 'MoneyWithdrawn': {
        const acc = this.ledger.get(event.id)!;
        this.ledger.set(event.id, { ...acc, balance: acc.balance - event.amount, txCount: acc.txCount + 1 });
        break;
      }
    }
  }

  getBalance(id: string) { return this.ledger.get(id)?.balance ?? 0; }
  getAll()               { return Object.fromEntries(this.ledger); }
}
```

**Key properties of event sourcing:**
- **Complete audit trail**: every state change is recorded forever
- **Time travel**: rebuild state at any point in history by replaying events up to that timestamp
- **Snapshots**: avoid replaying thousands of events by caching state at version N; only replay N+1 onward
- **Optimistic concurrency**: `expectedVersion` in `append()` prevents lost updates — if two processes load version 5 and both try to append, the second gets a conflict error
- **Projection flexibility**: add new read models by replaying historical events through new projectors — no schema migration needed

```typescript
// Saga orchestration: a central orchestrator drives each step
// and knows the compensating transaction for each

type SagaStep<TData> = {
  name: string;
  execute:    (data: TData) => Promise<TData>;
  compensate: (data: TData) => Promise<void>;
};

class SagaOrchestrator<TData> {
  private steps: SagaStep<TData>[] = [];
  private completedSteps: SagaStep<TData>[] = [];

  addStep(step: SagaStep<TData>): this {
    this.steps.push(step);
    return this;
  }

  async execute(initialData: TData): Promise<TData> {
    let data = initialData;

    for (const step of this.steps) {
      try {
        console.log(`[Saga] Executing: ${step.name}`);
        data = await step.execute(data);
        this.completedSteps.push(step);
      } catch (err) {
        console.error(`[Saga] Failed at ${step.name}:`, err);
        await this.rollback(data);
        throw new SagaFailedError(step.name, err as Error);
      }
    }
    return data;
  }

  private async rollback(data: TData): Promise<void> {
    // Compensate in reverse order
    const toCompensate = [...this.completedSteps].reverse();
    console.log(`[Saga] Rolling back ${toCompensate.length} completed steps`);

    for (const step of toCompensate) {
      try {
        console.log(`[Saga] Compensating: ${step.name}`);
        await step.compensate(data);
      } catch (compensationErr) {
        // Log but continue — partial rollback is better than no rollback
        console.error(`[Saga] Compensation failed for ${step.name}:`, compensationErr);
        // In production: alert ops team, persist failed compensation for manual intervention
      }
    }
  }
}

class SagaFailedError extends Error {
  constructor(public readonly failedStep: string, public readonly cause: Error) {
    super(`Saga failed at step '${failedStep}': ${cause.message}`);
    this.name = 'SagaFailedError';
  }
}

// ============================================================
// ORDER FULFILLMENT SAGA
// ============================================================
interface OrderContext {
  orderId:       string;
  customerId:    string;
  items:         { productId: string; qty: number; price: number }[];
  totalAmount:   number;
  // Populated by steps
  reservationId?:    string;
  paymentId?:        string;
  shipmentId?:       string;
}

// Step 1: Reserve inventory
const reserveInventory: SagaStep<OrderContext> = {
  name: 'ReserveInventory',
  execute: async (ctx) => {
    const reservationId = await inventoryService.reserve(ctx.items);
    return { ...ctx, reservationId };
  },
  compensate: async (ctx) => {
    if (ctx.reservationId) {
      await inventoryService.release(ctx.reservationId);
    }
  },
};

// Step 2: Charge payment
const chargePayment: SagaStep<OrderContext> = {
  name: 'ChargePayment',
  execute: async (ctx) => {
    const paymentId = await paymentService.charge(ctx.customerId, ctx.totalAmount, ctx.orderId);
    return { ...ctx, paymentId };
  },
  compensate: async (ctx) => {
    if (ctx.paymentId) {
      await paymentService.refund(ctx.paymentId, ctx.totalAmount, 'Order saga rollback');
    }
  },
};

// Step 3: Create shipment
const createShipment: SagaStep<OrderContext> = {
  name: 'CreateShipment',
  execute: async (ctx) => {
    const shipmentId = await shippingService.create(ctx.orderId, ctx.items, ctx.customerId);
    return { ...ctx, shipmentId };
  },
  compensate: async (ctx) => {
    if (ctx.shipmentId) {
      await shippingService.cancel(ctx.shipmentId);
    }
  },
};

// Step 4: Confirm order (no compensation needed — it's the final success step)
const confirmOrder: SagaStep<OrderContext> = {
  name: 'ConfirmOrder',
  execute: async (ctx) => {
    await orderService.confirm(ctx.orderId, {
      reservationId: ctx.reservationId!,
      paymentId: ctx.paymentId!,
      shipmentId: ctx.shipmentId!,
    });
    return ctx;
  },
  compensate: async (ctx) => {
    await orderService.cancel(ctx.orderId, 'Saga rollback');
  },
};

// ---- Run the saga ----
async function fulfillOrder(order: OrderContext): Promise<OrderContext> {
  const saga = new SagaOrchestrator<OrderContext>()
    .addStep(reserveInventory)
    .addStep(chargePayment)
    .addStep(createShipment)
    .addStep(confirmOrder);

  return saga.execute(order);
}

// Example: shippingService throws → inventory released, payment refunded
try {
  const fulfilled = await fulfillOrder({
    orderId: 'order-789',
    customerId: 'cust-123',
    items: [{ productId: 'sku-1', qty: 2, price: 49.99 }],
    totalAmount: 99.98,
  });
} catch (err) {
  if (err instanceof SagaFailedError) {
    console.error(`Order failed at: ${err.failedStep}`);
    // Send customer notification, update order status to 'failed'
  }
}
```

**Saga vs 2PC (Two-Phase Commit):**
- 2PC requires all participants to hold locks during the protocol — doesn't work across microservices or external APIs
- Saga uses **compensating transactions** (business-level undo) instead of locks — each step has its own local ACID transaction
- Trade-off: saga is **eventually consistent**, not immediately consistent. A window exists where partial state is visible
- Idempotency is critical: compensation calls may be retried on network failures — each service must handle duplicate requests safely

## Primitive Obsession + Inappropriate Intimacy

### Before: Raw primitives everywhere

```typescript
// BAD: primitive obsession — strings and numbers carry no domain meaning
interface Order {
  id: string;         // is this a UUID? sequential? What format?
  customerId: string; // same question
  email: string;      // no validation
  total: number;      // dollars? cents? what currency?
  status: string;     // what values are valid?
  createdAt: string;  // ISO string? timestamp?
  shippingAddress: string; // one long string — impossible to work with
}

// BAD: inappropriate intimacy — Order directly manipulates Customer internals
class OrderProcessor {
  processRefund(order: Order, customer: Customer) {
    // OrderProcessor pokes directly into Customer's wallet details
    if (customer.wallet.balance >= order.total) {
      customer.wallet.balance -= order.total;     // directly mutating!
      customer.wallet.transactions.push({         // and its private collection!
        type: 'debit', amount: order.total, date: new Date().toISOString()
      });
      customer.loyaltyPoints += Math.floor(order.total * 10); // again direct mutation
      order.status = 'refunded';
    }
  }
}
```

### After: Value objects eliminate primitive obsession

```typescript
// Value Objects — immutable, self-validating, comparable by value
class OrderId {
  private constructor(readonly value: string) {}
  static create(): OrderId { return new OrderId(`ord_${crypto.randomUUID()}`); }
  static fromString(s: string): OrderId {
    if (!/^ord_[0-9a-f-]{36}$/.test(s)) throw new Error(`Invalid OrderId: ${s}`);
    return new OrderId(s);
  }
  equals(other: OrderId) { return this.value === other.value; }
  toString() { return this.value; }
}

class Money {
  private constructor(readonly cents: number, readonly currency: string) {}

  static of(amount: number, currency: string): Money {
    if (amount < 0) throw new Error('Money cannot be negative');
    if (!/^[A-Z]{3}$/.test(currency)) throw new Error(`Invalid currency: ${currency}`);
    return new Money(Math.round(amount * 100), currency);
  }

  add(other: Money): Money {
    if (this.currency !== other.currency) throw new Error('Currency mismatch');
    return new Money(this.cents + other.cents, this.currency);
  }

  subtract(other: Money): Money {
    if (this.cents < other.cents) throw new Error('Insufficient amount');
    return new Money(this.cents - other.cents, this.currency);
  }

  get amount(): number { return this.cents / 100; }
  toString() { return `${this.currency} ${this.amount.toFixed(2)}`; }
  equals(other: Money) { return this.cents === other.cents && this.currency === other.currency; }
}

class Email {
  private constructor(readonly value: string) {}
  static of(raw: string): Email {
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(raw)) throw new Error(`Invalid email: ${raw}`);
    return new Email(raw.toLowerCase());
  }
}

type OrderStatus = 'pending' | 'confirmed' | 'shipped' | 'delivered' | 'refunded' | 'cancelled';

class ShippingAddress {
  constructor(
    public readonly street: string,
    public readonly city: string,
    public readonly country: string,
    public readonly postalCode: string,
  ) {
    if (!street || !city || !country) throw new Error('Address fields required');
  }
  format() { return `${this.street}, ${this.city}, ${this.country} ${this.postalCode}`; }
}

// Domain entity with value objects
class Order {
  private constructor(
    public readonly id: OrderId,
    public readonly customerId: string,
    public readonly total: Money,
    public readonly shippingAddress: ShippingAddress,
    private _status: OrderStatus,
    public readonly createdAt: Date,
  ) {}

  static create(customerId: string, total: Money, address: ShippingAddress): Order {
    return new Order(OrderId.create(), customerId, total, address, 'pending', new Date());
  }

  get status() { return this._status; }

  confirm() {
    if (this._status !== 'pending') throw new Error(`Cannot confirm order in status '${this._status}'`);
    this._status = 'confirmed';
  }

  // Order manages its OWN state transitions — doesn't need outsiders to set status directly
  markRefunded() {
    if (!['confirmed', 'shipped', 'delivered'].includes(this._status)) {
      throw new Error(`Cannot refund order in status '${this._status}'`);
    }
    this._status = 'refunded';
  }
}

// Fix inappropriate intimacy — Customer handles its own wallet
class Customer {
  private _balance: Money;
  private _loyaltyPoints: number;

  constructor(readonly id: string, initialBalance: Money, points = 0) {
    this._balance = initialBalance;
    this._loyaltyPoints = points;
  }

  // Customer owns its own business logic — no external mutation
  creditRefund(amount: Money): void {
    this._balance = this._balance.add(amount);
    this._loyaltyPoints += Math.floor(amount.amount * 10);
  }

  get balance()       { return this._balance; }
  get loyaltyPoints() { return this._loyaltyPoints; }
}

// OrderProcessor orchestrates — doesn't mutate internals of either object
class OrderProcessor {
  processRefund(order: Order, customer: Customer): void {
    order.markRefunded();           // Order validates its own state transition
    customer.creditRefund(order.total); // Customer handles its own wallet logic
    // Neither class pokes into the other's internals
  }
}
```

**Smells fixed:**
- `string` → `OrderId`, `Email`; `number` → `Money`: domain rules encoded once, validated at construction
- `string` status → `OrderStatus` union: only valid values computable at type level
- `string` address → `ShippingAddress`: individual fields accessible, formatting centralized
- Inappropriate intimacy: `OrderProcessor` no longer directly modifies `customer.wallet.balance` or `customer.wallet.transactions` — `Customer` owns that logic

```typescript
// Semaphore — limits concurrent executions
class Semaphore {
  private queue: (() => void)[] = [];
  private running = 0;

  constructor(private readonly limit: number) {
    if (limit < 1) throw new Error('Semaphore limit must be >= 1');
  }

  async acquire(): Promise<void> {
    if (this.running < this.limit) {
      this.running++;
      return;
    }
    // Queue the waiter
    await new Promise<void>(resolve => this.queue.push(resolve));
  }

  release(): void {
    const next = this.queue.shift();
    if (next) {
      next();  // wake next waiter (running count stays the same)
    } else {
      this.running--;
    }
  }

  async run<T>(fn: () => Promise<T>): Promise<T> {
    await this.acquire();
    try { return await fn(); }
    finally { this.release(); }
  }

  get stats() { return { running: this.running, queued: this.queue.length, limit: this.limit }; }
}

// Bulkhead — wraps a semaphore with queue depth limiting and timeout
interface BulkheadOptions {
  name:            string;
  maxConcurrent:   number;   // thread pool size
  maxQueue:        number;   // max pending requests before rejection
  timeoutMs?:      number;   // max wait time in queue
  onReject?:       (name: string, reason: 'full' | 'timeout') => void;
}

class Bulkhead {
  private semaphore: Semaphore;
  private queueDepth = 0;
  private rejected   = 0;
  private completed  = 0;

  constructor(private opts: BulkheadOptions) {
    this.semaphore = new Semaphore(opts.maxConcurrent);
  }

  async execute<T>(fn: () => Promise<T>): Promise<T> {
    const { maxQueue, timeoutMs, name, onReject } = this.opts;

    // Check queue capacity BEFORE acquiring semaphore
    if (this.queueDepth >= maxQueue) {
      this.rejected++;
      onReject?.(name, 'full');
      throw new BulkheadRejectedError(name, 'Queue full');
    }

    this.queueDepth++;
    try {
      // Optionally time-box the queue wait
      const acquire = this.semaphore.acquire();
      if (timeoutMs) {
        const timeout = new Promise<never>((_, reject) =>
          setTimeout(() => reject(new BulkheadRejectedError(name, 'Queue timeout')), timeoutMs)
        );
        await Promise.race([acquire, timeout]).catch(err => {
          this.rejected++;
          onReject?.(name, 'timeout');
          throw err;
        });
      } else {
        await acquire;
      }
    } finally {
      this.queueDepth--;
    }

    try {
      return await fn();
    } finally {
      this.semaphore.release();
      this.completed++;
    }
  }

  getStats() {
    return {
      name:      this.opts.name,
      ...this.semaphore.stats,
      rejected:  this.rejected,
      completed: this.completed,
    };
  }
}

class BulkheadRejectedError extends Error {
  constructor(bulkhead: string, reason: string) {
    super(`Bulkhead '${bulkhead}' rejected request: ${reason}`);
    this.name = 'BulkheadRejectedError';
  }
}

// ============================================================
// ISOLATION: payment and reporting use separate bulkheads
// ============================================================

// Payment bulkhead: small, strict — never let reporting starve payments
const paymentBulkhead = new Bulkhead({
  name: 'payments',
  maxConcurrent: 10,    // only 10 concurrent payment calls
  maxQueue: 20,         // up to 20 waiting
  timeoutMs: 5_000,     // fail fast if waiting more than 5s
  onReject: (name, reason) => metrics.increment(`bulkhead.${name}.rejected.${reason}`),
});

// Reporting bulkhead: larger pool, longer timeout — slower but isolated
const reportingBulkhead = new Bulkhead({
  name: 'reporting',
  maxConcurrent: 5,     // reports can be slow, fewer concurrent
  maxQueue: 50,         // larger queue — reports can wait
  timeoutMs: 30_000,
  onReject: (name, reason) => metrics.increment(`bulkhead.${name}.rejected.${reason}`),
});

// ---- Services using bulkheads ----
class PaymentService {
  async chargeCard(token: string, amount: number) {
    return paymentBulkhead.execute(() => stripe.charges.create({ amount, source: token }));
  }
}

class ReportingService {
  async generateSalesReport(dateRange: DateRange) {
    return reportingBulkhead.execute(() => db.query(heavyAggregationQuery(dateRange)));
  }
}

// ---- Health endpoint ----
app.get('/health/bulkheads', (_, res) => {
  res.json({
    payments:  paymentBulkhead.getStats(),
    reporting: reportingBulkhead.getStats(),
  });
});

// Example output when reporting is hammered:
// { payments:  { running: 2, queued: 0,  limit: 10, rejected: 0 } }
// { reporting: { running: 5, queued: 50, limit: 5,  rejected: 847 } }
// ↑ Reporting fully saturated but payment bulkhead is unaffected
```

**Why bulkheads matter:** Without isolation, a spike in slow report queries consumes all available async capacity (Node.js event loop isn't blocking but DB connection pools are shared). With bulkheads, the reporting pool saturates and new report requests get rejected with 503, while the payment pool remains at zero queue depth — business-critical operations are unaffected.

## Sidecar Pattern

The sidecar pattern deploys an auxiliary process alongside the main application container in the same pod (Kubernetes) or process group. The sidecar intercepts or augments the main service's traffic and telemetry — the main service stays clean of infrastructure concerns.

```
┌─────────────────────────────────────────────┐
│  Kubernetes Pod                             │
│  ┌─────────────────┐  ┌──────────────────┐  │
│  │  Main Service   │  │  Sidecar         │  │
│  │  (business      │◄─┤  - TLS termination│  │
│  │   logic only)   │  │  - Log enrichment │  │
│  │  :3000 HTTP     │  │  - Metrics        │  │
│  └─────────────────┘  │  :8443 HTTPS     │  │
│                        └──────────────────┘  │
└─────────────────────────────────────────────┘
```

### Main Service — pure business logic, plain HTTP

```typescript
// main-service/src/app.ts — knows NOTHING about TLS, observability, auth
import express from 'express';

const app = express();

app.get('/users/:id', async (req, res) => {
  const user = await db.users.findById(req.params.id);
  if (!user) return res.status(404).json({ error: 'Not found' });
  res.json(user);
});

app.post('/orders', async (req, res) => {
  const order = await orderService.create(req.body);
  res.status(201).json(order);
});

// Listens on plain HTTP, localhost only — sidecar handles external traffic
app.listen(3000, '127.0.0.1', () => console.log('Main service on :3000'));
```

### Sidecar — handles all infrastructure concerns

```typescript
// sidecar/src/sidecar.ts
import https from 'https';
import http  from 'http';
import { createProxyServer } from 'http-proxy';
import { readFileSync } from 'fs';
import { createLogger }  from 'winston';
import promClient from 'prom-client';

const log = createLogger({ /* winston config */ });

// ---- Metrics setup ----
const httpRequestDuration = new promClient.Histogram({
  name:    'http_request_duration_seconds',
  help:    'Request duration',
  labelNames: ['method', 'route', 'status_code', 'service'],
  buckets: [0.001, 0.005, 0.01, 0.05, 0.1, 0.5, 1, 5],
});

const httpRequestsTotal = new promClient.Counter({
  name:       'http_requests_total',
  help:       'Total request count',
  labelNames: ['method', 'status_code', 'service'],
});

// ---- Proxy to main service ----
const proxy = createProxyServer({
  target: 'http://127.0.0.1:3000',
  selfHandleResponse: true,  // so we can log response details
});

proxy.on('proxyRes', (proxyRes, req: any, res: any) => {
  const durationMs = Date.now() - req._startTime;
  const route = req._route ?? req.url;

  // Enrich structured log with context the main service doesn't have
  log.info('request', {
    method:       req.method,
    path:         req.url,
    statusCode:   proxyRes.statusCode,
    durationMs,
    requestId:    req.headers['x-request-id'] ?? generateId(),
    traceId:      req.headers['x-trace-id'],
    clientIp:     req.socket.remoteAddress,
    userAgent:    req.headers['user-agent'],
    serviceName:  process.env.SERVICE_NAME ?? 'unknown',
    podName:      process.env.POD_NAME,
    namespace:    process.env.NAMESPACE,
  });

  // Record Prometheus metrics
  httpRequestDuration.observe(
    { method: req.method, route, status_code: String(proxyRes.statusCode), service: process.env.SERVICE_NAME ?? 'unknown' },
    durationMs / 1000
  );
  httpRequestsTotal.inc({ method: req.method, status_code: String(proxyRes.statusCode), service: process.env.SERVICE_NAME ?? 'unknown' });

  // Forward response
  res.writeHead(proxyRes.statusCode!, proxyRes.headers);
  proxyRes.pipe(res);
});

proxy.on('error', (err, req, res: any) => {
  log.error('proxy_error', { error: err.message, url: (req as any).url });
  res.writeHead(502);
  res.end(JSON.stringify({ error: 'Bad Gateway' }));
});

// ---- HTTPS server (TLS termination) ----
const tlsOptions = {
  cert: readFileSync('/etc/tls/cert.pem'),
  key:  readFileSync('/etc/tls/key.pem'),
  // Mutual TLS for service-to-service
  ca:          readFileSync('/etc/tls/ca.pem'),
  requestCert: process.env.MTLS === 'true',
};

const httpsServer = https.createServer(tlsOptions, (req: any, res) => {
  req._startTime = Date.now();

  // mTLS: extract peer certificate identity
  const cert = (req.socket as any).getPeerCertificate?.();
  if (cert?.subject) req.headers['x-client-id'] = cert.subject.CN;

  // Rate limit check (sidecar responsibility)
  if (!rateLimiter.allow(req.socket.remoteAddress!)) {
    res.writeHead(429, { 'Retry-After': '1' });
    res.end();
    return;
  }

  proxy.web(req, res);
});

httpsServer.listen(8443, () => console.log('Sidecar HTTPS proxy on :8443'));

// ---- Metrics endpoint (scraped by Prometheus, main service never exposes this) ----
const metricsServer = http.createServer(async (req, res) => {
  if (req.url === '/metrics') {
    res.setHeader('Content-Type', promClient.register.contentType);
    res.end(await promClient.register.metrics());
  } else {
    res.writeHead(404); res.end();
  }
});
metricsServer.listen(9090, '127.0.0.1', () => console.log('Metrics on :9090'));
```

```yaml
# kubernetes/pod.yaml — both containers share network namespace
apiVersion: v1
kind: Pod
spec:
  containers:
  - name: main-service
    image: my-service:latest
    ports: [{ containerPort: 3000 }]
    env: [{ name: POD_NAME, valueFrom: { fieldRef: { fieldPath: metadata.name } } }]

  - name: sidecar
    image: my-sidecar:latest
    ports:
      - { containerPort: 8443, name: https }
      - { containerPort: 9090, name: metrics }
    env:
      - { name: SERVICE_NAME, value: my-service }
      - { name: MTLS, value: "true" }
    volumeMounts: [{ name: tls-certs, mountPath: /etc/tls }]
```

**Separation of concerns achieved:** Main service is plain Node.js HTTP on localhost — no TLS code, no Prometheus client, no log enrichment. The sidecar intercepts all external traffic and enriches observability data with infrastructure context (pod name, namespace, mTLS identity) that the main service couldn't easily access anyway. Swapping from Prometheus to Datadog requires changing only the sidecar.

## Chain of Responsibility: Composable Middleware Pipeline

```typescript
type NextFn = () => Promise<void>;

interface Middleware<TCtx> {
  handle(ctx: TCtx, next: NextFn): Promise<void>;
}

class Pipeline<TCtx> {
  private middlewares: Middleware<TCtx>[] = [];

  use(mw: Middleware<TCtx>): this { this.middlewares.push(mw); return this; }

  useFunction(fn: (ctx: TCtx, next: NextFn) => Promise<void>): this {
    return this.use({ handle: fn });
  }

  async execute(ctx: TCtx): Promise<void> {
    let index = -1;
    const dispatch = async (i: number): Promise<void> => {
      if (i <= index) throw new Error('next() called multiple times');
      index = i;
      const mw = this.middlewares[i];
      if (!mw) return; // end of chain
      await mw.handle(ctx, () => dispatch(i + 1));
    };
    return dispatch(0);
  }
}

interface ReqCtx {
  method: string;
  path: string;
  headers: Record<string, string>;
  userId?: string;
  response: { status: number; body: unknown };
  startTime: number;
}

// Stops chain if no valid auth token
class AuthMiddleware implements Middleware<ReqCtx> {
  async handle(ctx: ReqCtx, next: NextFn): Promise<void> {
    const token = ctx.headers['authorization']?.replace('Bearer ', '');
    if (!token) {
      ctx.response = { status: 401, body: { error: 'Unauthorized' } };
      return; // omit next() — chain stops here
    }
    ctx.userId = await verifyToken(token);
    await next(); // pass to next handler
  }
}

// Stops chain if rate limit exceeded
class RateLimitMiddleware implements Middleware<ReqCtx> {
  private buckets = new Map<string, { count: number; resetAt: number }>();
  async handle(ctx: ReqCtx, next: NextFn): Promise<void> {
    const key = ctx.userId ?? 'anon';
    const now = Date.now();
    const b   = this.buckets.get(key) ?? { count: 0, resetAt: now + 60_000 };
    if (now > b.resetAt) { b.count = 0; b.resetAt = now + 60_000; }
    b.count++;
    this.buckets.set(key, b);
    if (b.count > 100) {
      ctx.response = { status: 429, body: { error: 'Rate limit exceeded' } };
      return;
    }
    await next();
  }
}

// Calls next() first, then logs — wraps entire downstream chain
class LoggingMiddleware implements Middleware<ReqCtx> {
  async handle(ctx: ReqCtx, next: NextFn): Promise<void> {
    await next();
    console.log(`${ctx.method} ${ctx.path} ${ctx.response.status} ${Date.now() - ctx.startTime}ms`);
  }
}

// Fluent pipeline construction
const pipeline = new Pipeline<ReqCtx>()
  .use(new LoggingMiddleware())    // outermost — runs after all others
  .use(new AuthMiddleware())       // short-circuits on missing token
  .use(new RateLimitMiddleware())  // short-circuits on excess requests
  .useFunction(async ctx => {     // leaf handler — business logic
    ctx.response = { status: 200, body: { userId: ctx.userId } };
  });

await pipeline.execute({
  method: 'GET', path: '/api/me',
  headers: { authorization: 'Bearer valid-token' },
  response: { status: 0, body: null },
  startTime: Date.now(),
});
```

**Chain vs if/else:** Each handler is decoupled — `AuthMiddleware` has no knowledge of `RateLimitMiddleware`. Adding `CorsMiddleware` is a single `.use()` call with zero changes to existing handlers. Reordering is a config change, not a code change.

**Execution model (koa-style):** Calling `next()` dives deeper into the chain. Omitting `next()` short-circuits — nothing downstream executes. `LoggingMiddleware` wraps by calling `next()` first then logging, giving it access to the final response status.

## Template Method Pattern: ETL Pipeline

```python
from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Any
import csv, json, time

@dataclass
class Record:
    id: str
    data: dict[str, Any]

class DataPipeline(ABC):
    def run(self, source: str, destination: str) -> int:
        """Template method — defines the fixed algorithm skeleton."""
        start   = time.perf_counter()
        raw     = self.extract(source)           # must override
        records = self.transform(raw)            # must override
        records = self._validate(records)        # final — cannot override
        count   = self.load(records, destination) # must override
        self._on_complete(count, time.perf_counter() - start)  # hook
        return count

    @abstractmethod
    def extract(self, source: str) -> list[dict]: ...

    @abstractmethod
    def transform(self, raw: list[dict]) -> list[Record]: ...

    @abstractmethod
    def load(self, records: list[Record], destination: str) -> int: ...

    # Final step — base class always runs validation, subclasses cannot bypass
    def _validate(self, records: list[Record]) -> list[Record]:
        valid   = [r for r in records if r.id and r.data]
        skipped = len(records) - len(valid)
        if skipped:
            print(f'  Warning: skipped {skipped} invalid records')
        return valid

    # Hook — has a default, subclasses may optionally override
    def _on_complete(self, count: int, elapsed: float) -> None:
        print(f'  Loaded {count} records in {elapsed:.2f}s')

class CsvPipeline(DataPipeline):
    def __init__(self, delimiter: str = ',', encoding: str = 'utf-8'):
        self.delimiter = delimiter
        self.encoding  = encoding

    def extract(self, source: str) -> list[dict]:
        with open(source, encoding=self.encoding) as f:
            return list(csv.DictReader(f, delimiter=self.delimiter))

    def transform(self, raw: list[dict]) -> list[Record]:
        return [
            Record(
                id=row.get('id', ''),
                data={k: v.strip() for k, v in row.items() if k != 'id'}
            )
            for row in raw
        ]

    def load(self, records: list[Record], destination: str) -> int:
        with open(destination, 'w') as f:
            json.dump([{'id': r.id, **r.data} for r in records], f, indent=2)
        return len(records)

class JsonPipeline(DataPipeline):
    def __init__(self, id_field: str = '_id'):
        self.id_field = id_field

    def extract(self, source: str) -> list[dict]:
        with open(source) as f:
            data = json.load(f)
        return data if isinstance(data, list) else data.get('items', [])

    def transform(self, raw: list[dict]) -> list[Record]:
        return [
            Record(id=str(item.pop(self.id_field, item.get('id', ''))), data=item)
            for item in raw
        ]

    def load(self, records: list[Record], destination: str) -> int:
        import sqlite3
        con = sqlite3.connect(destination)
        con.execute('CREATE TABLE IF NOT EXISTS records (id TEXT PRIMARY KEY, data TEXT)')
        con.executemany('INSERT OR REPLACE INTO records VALUES (?, ?)',
                        [(r.id, json.dumps(r.data)) for r in records])
        con.commit()
        con.close()
        return len(records)

    # Override hook: JSON pipeline uses a different log format
    def _on_complete(self, count: int, elapsed: float) -> None:
        print(f'  [JsonPipeline] {count} records -> SQLite in {elapsed*1000:.0f}ms')

# Usage
CsvPipeline(delimiter=';').run('input.csv', 'output.json')
JsonPipeline(id_field='_id').run('data.json', 'records.db')
```

**Three method categories:**
- `extract/transform/load` — abstract, must be overridden (Python raises TypeError if not)
- `_validate` — concrete base implementation, intentionally not overridable by convention (prefix `_`)
- `_on_complete` — hook: has a working default but subclasses may specialize it

**Template Method vs Strategy:** Template Method uses class inheritance — subclasses fill in variable steps within a fixed skeleton. Strategy uses composition — the algorithm object is injected and can be swapped at runtime. Choose Template Method when the skeleton is stable and extension happens through subclassing; choose Strategy when you need runtime algorithm swapping.

## Data Clumps: From Raw Primitives to Value Objects

Data clumps are groups of fields/parameters that always appear together but have no enclosing type. Test: remove one field — if the rest lose meaning, it is a clump.

### Before: Primitives scattered across the codebase

```typescript
// BAD: lat/lng always appear together — 2-field clump
function findNearby(userLat: number, userLng: number, radiusKm: number): Place[] { return []; }

function calculateDistance(lat1: number, lng1: number, lat2: number, lng2: number): number {
  return 0; // haversine formula scattered here
}

function isInBounds(
  lat: number, lng: number,           // point
  minLat: number, maxLat: number,     // bounds — 6-field clump
  minLng: number, maxLng: number
): boolean { return true; }

// BAD: startDate/endDate always together — date range clump
function getReservations(userId: string, startDate: Date, endDate: Date): Reservation[] { return []; }
function countWorkdays(startDate: Date, endDate: Date): number { return 0; }
function datesOverlap(aStart: Date, aEnd: Date, bStart: Date, bEnd: Date): boolean { return false; }

// Caller: easy to swap lat/lng or start/end
const d = calculateDistance(user.lat, user.lng, venue.lat, venue.lng);
```

### After: Value objects

```typescript
class Coordinates {
  constructor(
    public readonly lat: number,
    public readonly lng: number,
  ) {
    if (lat < -90  || lat > 90)  throw new RangeError(`Invalid latitude: ${lat}`);
    if (lng < -180 || lng > 180) throw new RangeError(`Invalid longitude: ${lng}`);
  }

  // Domain logic lives HERE, not scattered across callers
  distanceTo(other: Coordinates): number {
    const R    = 6371;
    const dLat = toRad(other.lat - this.lat);
    const dLng = toRad(other.lng - this.lng);
    const a    = Math.sin(dLat/2)**2 +
                 Math.cos(toRad(this.lat)) * Math.cos(toRad(other.lat)) * Math.sin(dLng/2)**2;
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  }

  isWithinRadius(center: Coordinates, radiusKm: number): boolean {
    return this.distanceTo(center) <= radiusKm;
  }

  static fromGeoJSON([lng, lat]: [number, number]) { return new Coordinates(lat, lng); }
  toString() { return `(${this.lat.toFixed(6)}, ${this.lng.toFixed(6)})`; }
}

class BoundingBox {
  constructor(
    public readonly southwest: Coordinates,
    public readonly northeast: Coordinates,
  ) {}

  contains(p: Coordinates): boolean {
    return p.lat >= this.southwest.lat && p.lat <= this.northeast.lat &&
           p.lng >= this.southwest.lng && p.lng <= this.northeast.lng;
  }

  static fromCenter(center: Coordinates, radiusKm: number): BoundingBox {
    const dLat = radiusKm / 111;
    const dLng = radiusKm / (111 * Math.cos(toRad(center.lat)));
    return new BoundingBox(
      new Coordinates(center.lat - dLat, center.lng - dLng),
      new Coordinates(center.lat + dLat, center.lng + dLng),
    );
  }
}

class DateRange {
  constructor(public readonly start: Date, public readonly end: Date) {
    if (start > end) throw new RangeError('Start must be before end');
  }

  get durationDays() { return (this.end.getTime() - this.start.getTime()) / 86_400_000; }

  overlaps(other: DateRange): boolean {
    return this.start < other.end && this.end > other.start;
  }

  contains(date: Date): boolean { return date >= this.start && date <= this.end; }

  countWorkdays(): number {
    let count = 0;
    const d   = new Date(this.start);
    while (d <= this.end) {
      if (d.getDay() !== 0 && d.getDay() !== 6) count++;
      d.setDate(d.getDate() + 1);
    }
    return count;
  }

  static lastNDays(n: number): DateRange {
    return new DateRange(new Date(Date.now() - n * 86_400_000), new Date());
  }
}

// Clean, impossible-to-swap signatures
function findNearby(location: Coordinates, radiusKm: number): Place[] {
  return allPlaces.filter(p => p.location.isWithinRadius(location, radiusKm));
}

function getReservations(userId: string, period: DateRange): Reservation[] {
  return db.reservations.where({ userId, overlaps: period });
}

// Usage
const userLoc   = new Coordinates(51.5074, -0.1278);
const nearby    = findNearby(userLoc, 5.0);

const thisWeek  = new DateRange(new Date('2024-03-11'), new Date('2024-03-15'));
const workdays  = thisWeek.countWorkdays();  // 5
```

**Result of refactoring:**
- `(lat, lng)` → `Coordinates`: 2 params → 1, validation + haversine centralized
- `(lat, lng, minLat, maxLat, minLng, maxLng)` → `(Coordinates, BoundingBox)`: 6 params → 2
- `(startDate, endDate)` → `DateRange`: overlap/workday logic is now a method, not repeated everywhere
- Argument swap bugs impossible: `new Coordinates(lat, lng)` is self-documenting

## Proxy Pattern: Virtual and Protection Proxies

```typescript
// ---- Virtual Proxy: lazy loading ----
interface ImageLoader {
  render(): Promise<HTMLImageElement | null>;
  getMetadata(): { width: number; height: number; url: string };
}

class HeavyImage implements ImageLoader {
  private element: HTMLImageElement;
  constructor(private url: string, private width: number, private height: number) {
    this.element = new Image(width, height);
    this.element.src = url;
    console.log(`[HeavyImage] Loaded: ${url}`);
  }
  async render() {
    await new Promise<void>((res, rej) => {
      if (this.element.complete) return res();
      this.element.onload  = () => res();
      this.element.onerror = () => rej(new Error(`Load failed: ${this.url}`));
    });
    return this.element;
  }
  getMetadata() { return { width: this.width, height: this.height, url: this.url }; }
}

// Proxy: HeavyImage not created until first call to render()
class LazyImageProxy implements ImageLoader {
  private real: HeavyImage | null = null;
  constructor(private url: string, private width: number, private height: number) {}

  async render() {
    if (!this.real) {
      console.log(`[Proxy] Creating HeavyImage for ${this.url}`);
      this.real = new HeavyImage(this.url, this.width, this.height);
    }
    return this.real.render();
  }

  // Metadata available without loading the image
  getMetadata() { return { width: this.width, height: this.height, url: this.url }; }
}

// 100 images — none loaded until scrolled into view
const gallery: ImageLoader[] = Array.from({ length: 100 }, (_, i) =>
  new LazyImageProxy(`/img/photo-${i}.jpg`, 800, 600)
);

// Only img[0] loads when user scrolls to it
await gallery[0].render();
// All metadata available instantly (no network)
gallery.map(img => img.getMetadata().url); // fast

// ---- Protection Proxy: access control ----
interface DocumentService {
  read(docId: string): Promise<string>;
  write(docId: string, content: string): Promise<void>;
  delete(docId: string): Promise<void>;
}

class RealDocumentService implements DocumentService {
  async read(id: string)             { return `Content of ${id}`; }
  async write(id: string, c: string) { console.log(`Written ${id}`); }
  async delete(id: string)           { console.log(`Deleted ${id}`); }
}

type DocAction = 'read' | 'write' | 'delete';

class ProtectionProxy implements DocumentService {
  private acl: Record<DocAction, string[]> = {
    read:   ['viewer', 'editor', 'admin'],
    write:  ['editor', 'admin'],
    delete: ['admin'],
  };

  constructor(private real: DocumentService, private userRoles: string[]) {}

  private guard(action: DocAction): void {
    const permitted = this.acl[action].some(r => this.userRoles.includes(r));
    if (!permitted) throw new Error(`Permission denied: cannot ${action}`);
  }

  async read(id: string)             { this.guard('read');   return this.real.read(id); }
  async write(id: string, c: string) { this.guard('write');  return this.real.write(id, c); }
  async delete(id: string)           { this.guard('delete'); return this.real.delete(id); }
}

// Caller cannot distinguish proxy from real — same interface
function useDocService(svc: DocumentService) {
  return svc.read('doc-1'); // works with real or proxy
}

const editorSvc = new ProtectionProxy(new RealDocumentService(), ['editor']);
await editorSvc.read('doc-1');           // OK — editor can read
await editorSvc.write('doc-1', 'text'); // OK — editor can write
await editorSvc.delete('doc-1');        // throws: Permission denied
```

**Three canonical proxy variants:**
- **Virtual**: defers creation/loading until first use — lazy loading, connection pools, ORM relationships
- **Protection**: gates access without touching the real subject — RBAC, capability-based auth
- **Remote**: makes a network resource look local — gRPC stubs, REST client wrappers

All implement the target interface; the caller receives `ImageLoader` or `DocumentService` and cannot tell which variant it holds.

## Replace Conditional with Polymorphism

### Before: Type-switching across multiple functions

```typescript
// BAD: adding a new carrier ('fedex') requires touching 3 functions
type Carrier = 'ups' | 'usps' | 'dhl';

function calculateShipping(carrier: Carrier, weightKg: number, distanceKm: number): number {
  if (carrier === 'ups')  return 5.00 + weightKg * 0.85 + distanceKm * 0.02;
  if (carrier === 'usps') return 3.50 + weightKg * 0.70;       // flat rate after base
  if (carrier === 'dhl')  return 8.00 + weightKg * 1.20 + distanceKm * 0.03;
  throw new Error(`Unknown carrier: ${carrier}`);
}

function estimateDeliveryDays(carrier: Carrier, distanceKm: number): number {
  if (carrier === 'ups')  return Math.ceil(distanceKm / 800);
  if (carrier === 'usps') return Math.ceil(distanceKm / 500);
  if (carrier === 'dhl')  return Math.ceil(distanceKm / 1200); // faster
  throw new Error(`Unknown carrier: ${carrier}`);
}

function formatTrackingUrl(carrier: Carrier, trackingId: string): string {
  if (carrier === 'ups')  return `https://ups.com/track?id=${trackingId}`;
  if (carrier === 'usps') return `https://usps.com/track/${trackingId}`;
  if (carrier === 'dhl')  return `https://dhl.com/tracking?n=${trackingId}`;
  throw new Error(`Unknown carrier: ${carrier}`);
}
```

### After: Polymorphism — each carrier is self-contained

```typescript
// Strategy interface — each carrier implements this contract
interface ShippingCarrier {
  readonly id: string;
  readonly name: string;
  calculateCost(weightKg: number, distanceKm: number): number;
  estimateDeliveryDays(distanceKm: number): number;
  formatTrackingUrl(trackingId: string): string;
}

class UPSCarrier implements ShippingCarrier {
  readonly id   = 'ups';
  readonly name = 'UPS';
  calculateCost(w: number, d: number)     { return 5.00 + w * 0.85 + d * 0.02; }
  estimateDeliveryDays(d: number)         { return Math.ceil(d / 800); }
  formatTrackingUrl(id: string)           { return `https://ups.com/track?id=${id}`; }
}

class USPSCarrier implements ShippingCarrier {
  readonly id   = 'usps';
  readonly name = 'USPS';
  calculateCost(w: number, _d: number)   { return 3.50 + w * 0.70; }
  estimateDeliveryDays(d: number)        { return Math.ceil(d / 500); }
  formatTrackingUrl(id: string)          { return `https://usps.com/track/${id}`; }
}

class DHLCarrier implements ShippingCarrier {
  readonly id   = 'dhl';
  readonly name = 'DHL';
  calculateCost(w: number, d: number)   { return 8.00 + w * 1.20 + d * 0.03; }
  estimateDeliveryDays(d: number)       { return Math.ceil(d / 1200); }
  formatTrackingUrl(id: string)         { return `https://dhl.com/tracking?n=${id}`; }
}

// Adding FedEx: write ONE class, nothing else changes (Open/Closed Principle)
class FedExCarrier implements ShippingCarrier {
  readonly id   = 'fedex';
  readonly name = 'FedEx';
  calculateCost(w: number, d: number)   { return 6.50 + w * 0.95 + d * 0.025; }
  estimateDeliveryDays(d: number)       { return Math.ceil(d / 1000); }
  formatTrackingUrl(id: string)         { return `https://fedex.com/tracking?tracknumbers=${id}`; }
}

// Registry maps string IDs to carrier instances
class CarrierRegistry {
  private carriers = new Map<string, ShippingCarrier>();

  register(carrier: ShippingCarrier): this {
    this.carriers.set(carrier.id, carrier);
    return this;
  }

  get(id: string): ShippingCarrier {
    const carrier = this.carriers.get(id);
    if (!carrier) throw new Error(`Unknown carrier: ${id}`);
    return carrier;
  }

  all(): ShippingCarrier[] { return [...this.carriers.values()]; }

  cheapest(weightKg: number, distanceKm: number): ShippingCarrier {
    return this.all().reduce((best, c) =>
      c.calculateCost(weightKg, distanceKm) < best.calculateCost(weightKg, distanceKm) ? c : best
    );
  }
}

const registry = new CarrierRegistry()
  .register(new UPSCarrier())
  .register(new USPSCarrier())
  .register(new DHLCarrier())
  .register(new FedExCarrier()); // no other files changed

// Application code
function quoteShipment(carrierId: string, weightKg: number, distanceKm: number) {
  const carrier = registry.get(carrierId);
  return {
    cost:     carrier.calculateCost(weightKg, distanceKm),
    days:     carrier.estimateDeliveryDays(distanceKm),
    carrier:  carrier.name,
  };
}

// Find cheapest carrier automatically
const best = registry.cheapest(2.5, 500);
console.log(`Best: ${best.name} at $${best.calculateCost(2.5, 500).toFixed(2)}`);
```

**Open/Closed Principle in action:** The carrier interface is closed for modification (callers never change). Adding a new carrier is open via a new class + one `.register()` call. The three type-switching functions (calculateShipping, estimateDeliveryDays, formatTrackingUrl) are now zero lines of branching code.

## Shotgun Surgery: Notification System

Shotgun surgery occurs when one logical change — adding a new notification channel — requires editing many unrelated files. Each file is a separate blast site.

### Before: 6 files to add Slack

```typescript
// user-service.ts — change 1
import { sendEmail } from './email';
import { sendSMS }   from './sms';
// To add Slack: import { sendSlack } from './slack';

async function createUser(user: User) {
  await sendEmail(user.email, 'Welcome!', template(user));
  await sendSMS(user.phone, `Welcome ${user.name}`);
  // Change 2: await sendSlack(user.slackId, 'Welcome!');
}

// order-service.ts — change 3
async function shipOrder(order: Order) {
  await sendEmail(order.customer.email, 'Shipped!', shipTemplate(order));
  // Change 4: await sendSlack(order.customer.slackId, `Order ${order.id} shipped`);
}

// payment-service.ts — change 5
async function paymentFailed(payment: Payment) {
  await sendEmail(payment.customer.email, 'Payment failed', failTemplate(payment));
  // Change 6: await sendSlack(payment.customer.slackId, 'Payment failed');
}
```

### After: 1 file to add Slack

```typescript
// ---- Notification contract ----
export interface NotificationChannel {
  readonly id: string;
  canNotify(userId: string): Promise<boolean>;
  send(userId: string, event: NotificationEvent): Promise<void>;
}

export interface NotificationEvent {
  type:    string;
  subject: string;
  body:    string;
}

// ---- Notification service — orchestrates all channels ----
export class NotificationService {
  private channels = new Map<string, NotificationChannel>();

  register(channel: NotificationChannel): this {
    this.channels.set(channel.id, channel);
    return this;
  }

  async notify(userId: string, event: NotificationEvent, channelIds?: string[]): Promise<void> {
    const prefs    = await db.notificationPrefs.get(userId);
    const enabled  = channelIds ?? prefs.enabledChannels;
    const targets  = [...this.channels.values()].filter(c => enabled.includes(c.id));

    // Fan out to all enabled channels — don't fail if one channel errors
    const results = await Promise.allSettled(
      targets.map(async ch => {
        if (await ch.canNotify(userId)) await ch.send(userId, event);
      })
    );

    for (const r of results) {
      if (r.status === 'rejected') console.error('[Notify] Channel error:', r.reason);
    }
  }
}

// ---- Concrete channels ----
class EmailChannel implements NotificationChannel {
  readonly id = 'email';
  async canNotify(userId: string) { return !!(await db.users.find(userId))?.email; }
  async send(userId: string, event: NotificationEvent) {
    const user = await db.users.find(userId);
    if (!user?.email) return;
    await mailer.send({ to: user.email, subject: event.subject, html: event.body });
  }
}

class SMSChannel implements NotificationChannel {
  readonly id = 'sms';
  async canNotify(userId: string) { return !!(await db.users.find(userId))?.phone; }
  async send(userId: string, event: NotificationEvent) {
    const user = await db.users.find(userId);
    if (!user?.phone) return;
    await smsClient.send({ to: user.phone, message: event.body });
  }
}

// ---- ADD SLACK: ONE new file, zero other changes ----
class SlackChannel implements NotificationChannel {
  readonly id = 'slack';
  async canNotify(userId: string) { return !!(await db.users.find(userId))?.slackUserId; }
  async send(userId: string, event: NotificationEvent) {
    const user = await db.users.find(userId);
    if (!user?.slackUserId) return;
    await slackClient.chat.postMessage({
      channel: user.slackUserId,
      text: `*${event.subject}*\n${event.body}`,
    });
  }
}

// ---- Composition root: register channels here ----
export const notifications = new NotificationService()
  .register(new EmailChannel())
  .register(new SMSChannel())
  .register(new SlackChannel()); // ← only change to add Slack

// ---- Services: channel-agnostic, never change again ----
async function createUser(user: User) {
  await notifications.notify(user.id, {
    type:    'user.registered',
    subject: 'Welcome!',
    body:    welcomeTemplate(user),
  });
}

async function shipOrder(order: Order) {
  await notifications.notify(order.customerId, {
    type:    'order.shipped',
    subject: `Order ${order.id} shipped`,
    body:    shipTemplate(order),
  });
}
```

**Before vs After:**
| Adding Slack | Before | After |
|---|---|---|
| Files changed | 6 | 1 (new) |
| Existing files modified | 5 | 0 |
| Risk of regression | High | None |

**Open/Closed Principle applied:** The notification system is open for extension (new channel classes) and closed for modification (existing services never change). Each service calls `notifications.notify()` and is completely decoupled from how notifications are delivered.

## Primitive Obsession: From Raw Primitives to Value Objects

### Before: Primitives carry hidden contracts

```typescript
// BAD: what format is orderId? UUID? sequential? What currency is amount?
// What email validation happened? None of these questions are answerable from the type.
interface Order {
  orderId:    string;   // UUID? or 'ORD-001'?
  customerId: string;   // same ambiguity
  email:      string;   // validated? normalized?
  amount:     number;   // dollars? cents? EUR? USD?
  currency:   string;   // 'USD', 'usd', '$'?
  status:     string;   // any string? 'pending'? 'PENDING'?
  createdAt:  string;   // ISO? timestamp? local?
}

// Functions scatter validation logic everywhere
function sendConfirmation(email: string) {
  if (!email.includes('@')) throw new Error('Bad email'); // duplicated everywhere
  mailer.send(email, 'Confirmed');
}

function refund(amount: number, currency: string) {
  if (amount < 0) throw new Error('Amount negative'); // duplicated everywhere
  stripe.refund({ amount: amount * 100, currency });
}
```

### After: Value objects with validation and domain methods

```typescript
// ---- Value objects — validated at construction, immutable ----

class OrderId {
  private constructor(readonly value: string) {}

  static create(): OrderId {
    return new OrderId(`ord_${crypto.randomUUID()}`);
  }

  static fromString(s: string): OrderId {
    if (!/^ord_[0-9a-f-]{36}$/.test(s))
      throw new TypeError(`Invalid OrderId format: "${s}"`);
    return new OrderId(s);
  }

  equals(other: OrderId) { return this.value === other.value; }
  toString()             { return this.value; }
}

class Email {
  readonly value: string; // normalized

  private constructor(raw: string) {
    this.value = raw.toLowerCase().trim();
  }

  static of(raw: string): Email {
    if (typeof raw !== 'string' || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(raw.trim())) {
      throw new TypeError(`Invalid email: "${raw}"`);
    }
    return new Email(raw);
  }

  equals(other: Email) { return this.value === other.value; }
  domain()             { return this.value.split('@')[1]; }
  toString()           { return this.value; }
}

class Money {
  private constructor(
    readonly cents: number,      // always stored in smallest unit
    readonly currency: string,   // ISO 4217 uppercase
  ) {}

  static of(amount: number, currency: string): Money {
    if (!Number.isFinite(amount) || amount < 0)
      throw new RangeError(`Money amount must be non-negative finite: ${amount}`);
    if (!/^[A-Z]{3}$/.test(currency))
      throw new TypeError(`Invalid currency code: "${currency}"`);
    return new Money(Math.round(amount * 100), currency);
  }

  static ofCents(cents: number, currency: string): Money {
    return new Money(cents, currency);
  }

  add(other: Money): Money {
    if (this.currency !== other.currency)
      throw new Error(`Currency mismatch: ${this.currency} vs ${other.currency}`);
    return new Money(this.cents + other.cents, this.currency);
  }

  subtract(other: Money): Money {
    if (this.cents < other.cents)
      throw new RangeError('Result would be negative');
    return new Money(this.cents - other.cents, this.currency);
  }

  multiply(factor: number): Money {
    return new Money(Math.round(this.cents * factor), this.currency);
  }

  isGreaterThan(other: Money): boolean {
    if (this.currency !== other.currency) throw new Error('Currency mismatch');
    return this.cents > other.cents;
  }

  get amount(): number { return this.cents / 100; }
  equals(other: Money) { return this.cents === other.cents && this.currency === other.currency; }
  toString()           { return `${this.currency} ${this.amount.toFixed(2)}`; }
  format(locale = 'en-US') {
    return new Intl.NumberFormat(locale, { style: 'currency', currency: this.currency }).format(this.amount);
  }
}

type OrderStatus = 'pending' | 'confirmed' | 'shipped' | 'delivered' | 'cancelled';

// ---- Clean domain entity ----
class Order {
  private constructor(
    public readonly id: OrderId,
    public readonly customerId: string,
    public readonly customerEmail: Email,
    public readonly total: Money,
    private _status: OrderStatus,
    public readonly createdAt: Date,
  ) {}

  static create(customerId: string, email: Email, total: Money): Order {
    return new Order(OrderId.create(), customerId, email, total, 'pending', new Date());
  }

  get status() { return this._status; }

  confirm(): void {
    if (this._status !== 'pending')
      throw new Error(`Cannot confirm order in status '${this._status}'`);
    this._status = 'confirmed';
  }

  calculateTax(rate: number): Money {
    return this.total.multiply(rate);
  }

  totalWithTax(rate: number): Money {
    return this.total.add(this.calculateTax(rate));
  }
}

// ---- Usage — impossible to mix up currencies or pass a bad email ----
const order = Order.create(
  'cust-123',
  Email.of('jane@example.com'),
  Money.of(99.99, 'USD')
);

const tax   = order.calculateTax(0.08);           // Money USD 8.00
const total = order.totalWithTax(0.08);           // Money USD 107.99
console.log(total.format('en-US'));                // $107.99

// These throw at construction — bugs caught early
Email.of('not-an-email');                         // TypeError: Invalid email
Money.of(-5, 'usd');                              // TypeError: Invalid currency code
Money.of(10, 'USD').add(Money.of(5, 'EUR'));      // Error: Currency mismatch
```

**Why value objects improve correctness:**
- **Validated once**: `Email.of()` fails immediately with a clear message — no silent invalid emails flowing through the system
- **Immutable**: no other code can mutate `order.total.cents` directly
- **Self-documenting**: `Money.of(99.99, 'USD')` is unambiguous; `99.99` is not
- **Domain methods**: `total.format('fr-FR')` belongs on Money, not scattered across the app
- **Equality by value**: `email.equals(otherEmail)` is correct; `email === otherEmail` would always be false (reference comparison)

## CQRS: Blog Post Domain

```typescript
// ============================================================
// COMMANDS — intents to change state
// ============================================================
type CreatePostCommand  = { type: 'CreatePost';  id: string; title: string; content: string; authorId: string };
type PublishPostCommand = { type: 'PublishPost'; postId: string; publishedAt: Date };
type UpdateTitleCommand = { type: 'UpdateTitle'; postId: string; newTitle: string };
type Command = CreatePostCommand | PublishPostCommand | UpdateTitleCommand;

// Write model — rich domain object, validates invariants
class Post {
  private constructor(
    public readonly id: string,
    public title: string,
    public content: string,
    public readonly authorId: string,
    public status: 'draft' | 'published',
    public publishedAt: Date | null,
  ) {}

  static create(id: string, title: string, content: string, authorId: string): Post {
    if (!title.trim()) throw new Error('Title required');
    return new Post(id, title, content, authorId, 'draft', null);
  }

  publish(at: Date) {
    if (this.status === 'published') throw new Error('Already published');
    this.status = 'published';
    this.publishedAt = at;
  }

  updateTitle(title: string) {
    if (!title.trim()) throw new Error('Title required');
    this.title = title;
  }
}

interface PostWriteRepository {
  load(id: string): Promise<Post | null>;
  save(post: Post): Promise<void>;
}

// ============================================================
// COMMAND HANDLERS
// ============================================================
class PostCommandHandler {
  constructor(private repo: PostWriteRepository, private events: EventBus) {}

  async handle(cmd: Command): Promise<void> {
    switch (cmd.type) {
      case 'CreatePost': {
        const post = Post.create(cmd.id, cmd.title, cmd.content, cmd.authorId);
        await this.repo.save(post);
        await this.events.emit({ type: 'PostCreated', postId: cmd.id, title: cmd.title, authorId: cmd.authorId, ts: new Date() });
        break;
      }
      case 'PublishPost': {
        const post = await this.repo.load(cmd.postId);
        if (!post) throw new Error(`Post ${cmd.postId} not found`);
        post.publish(cmd.publishedAt);
        await this.repo.save(post);
        await this.events.emit({ type: 'PostPublished', postId: cmd.postId, ts: cmd.publishedAt });
        break;
      }
      case 'UpdateTitle': {
        const post = await this.repo.load(cmd.postId);
        if (!post) throw new Error(`Post ${cmd.postId} not found`);
        post.updateTitle(cmd.newTitle);
        await this.repo.save(post);
        await this.events.emit({ type: 'PostTitleUpdated', postId: cmd.postId, newTitle: cmd.newTitle, ts: new Date() });
        break;
      }
    }
  }
}

// ============================================================
// READ MODELS — denormalized, optimized per query pattern
// ============================================================
interface PostSummary {
  id: string; title: string; authorName: string;
  status: string; publishedAt: string | null; commentCount: number;
}

interface PostReadRepository {
  listSummaries(filter: { status?: string }, limit: number): Promise<PostSummary[]>;
  findById(id: string): Promise<PostSummary | null>;
  upsert(partial: Partial<PostSummary> & { id: string }): Promise<void>;
  incrementComments(postId: string): Promise<void>;
}

// ============================================================
// QUERY HANDLERS
// ============================================================
type ListPostsQuery = { type: 'ListPosts'; status?: string; limit: number };
type GetPostQuery   = { type: 'GetPost';   postId: string };
type Query = ListPostsQuery | GetPostQuery;

class PostQueryHandler {
  constructor(private readRepo: PostReadRepository) {}

  async handle(query: Query): Promise<unknown> {
    switch (query.type) {
      case 'ListPosts': return this.readRepo.listSummaries({ status: query.status }, query.limit);
      case 'GetPost':   return this.readRepo.findById(query.postId);
    }
  }
}

// ============================================================
// PROJECTOR — keeps read model in sync with events
// ============================================================
class PostProjector {
  constructor(
    private readRepo: PostReadRepository,
    private users:    { getName(id: string): Promise<string> },
  ) {}

  async on(event: DomainEvent): Promise<void> {
    switch (event.type) {
      case 'PostCreated': {
        const authorName = await this.users.getName(event.authorId);
        await this.readRepo.upsert({
          id: event.postId, title: event.title, authorName,
          status: 'draft', publishedAt: null, commentCount: 0,
        });
        break;
      }
      case 'PostPublished':
        await this.readRepo.upsert({ id: event.postId, status: 'published', publishedAt: event.ts.toISOString() });
        break;
      case 'PostTitleUpdated':
        await this.readRepo.upsert({ id: event.postId, title: event.newTitle });
        break;
      case 'CommentAdded':
        await this.readRepo.incrementComments(event.postId);
        break;
    }
  }
}

// ============================================================
// HTTP layer wires commands and queries
// ============================================================
router.post('/posts', async (req, res) => {
  await commandHandler.handle({ type: 'CreatePost', id: randomUUID(), ...req.body });
  res.status(202).json({ accepted: true }); // 202: side effects are async
});

router.get('/posts', async (req, res) => {
  const result = await queryHandler.handle({ type: 'ListPosts', limit: 20, status: req.query.status as string });
  res.json(result);
});
```

**CQRS benefits:**
- Read model can be a denormalized SQL view, Redis cache, or Elasticsearch index — optimized purely for query performance
- Write model enforces domain invariants independently of read optimization
- Read and write sides can be scaled independently
- Trade-off: **eventual consistency** — after a command, there is a brief window where queries return slightly stale data. For UIs, optimistic updates bridge this gap

## Saga Pattern: Distributed Order Fulfillment

```typescript
// Generic saga orchestrator — executes steps sequentially, rolls back on failure
type SagaStep<TData> = {
  name: string;
  execute:    (data: TData) => Promise<TData>;
  compensate: (data: TData) => Promise<void>;
};

class SagaOrchestrator<TData> {
  private steps:          SagaStep<TData>[] = [];
  private completedSteps: SagaStep<TData>[] = [];

  addStep(step: SagaStep<TData>): this { this.steps.push(step); return this; }

  async execute(initial: TData): Promise<TData> {
    let data = initial;

    for (const step of this.steps) {
      try {
        console.log(`[Saga] → ${step.name}`);
        data = await step.execute(data);
        this.completedSteps.push(step);
      } catch (err) {
        console.error(`[Saga] Failed at ${step.name}:`, (err as Error).message);
        await this.rollback(data);
        throw new SagaError(step.name, err as Error);
      }
    }
    return data;
  }

  private async rollback(data: TData): Promise<void> {
    const toCompensate = [...this.completedSteps].reverse();
    console.log(`[Saga] Rolling back ${toCompensate.length} completed steps`);

    for (const step of toCompensate) {
      try {
        console.log(`[Saga] ← Compensating ${step.name}`);
        await step.compensate(data);
      } catch (err) {
        // Log and continue — partial rollback is better than no rollback
        // In production: alert ops team, persist failure for manual intervention
        console.error(`[Saga] Compensation failed for ${step.name}:`, err);
      }
    }
  }
}

class SagaError extends Error {
  constructor(public readonly failedStep: string, public readonly cause: Error) {
    super(`Saga failed at '${failedStep}': ${cause.message}`);
    this.name = 'SagaError';
  }
}

// ---- Order fulfillment context ----
interface OrderCtx {
  orderId:       string;
  customerId:    string;
  items:         { productId: string; qty: number; price: number }[];
  totalAmount:   number;
  reservationId?: string;  // set by step 1
  paymentId?:    string;   // set by step 2
  shipmentId?:   string;   // set by step 3
}

// Step 1: Reserve inventory
const reserveInventory: SagaStep<OrderCtx> = {
  name: 'ReserveInventory',
  execute: async ctx => {
    const reservationId = await inventoryService.reserve(ctx.items);
    return { ...ctx, reservationId };
  },
  compensate: async ctx => {
    if (ctx.reservationId) await inventoryService.release(ctx.reservationId);
  },
};

// Step 2: Charge payment
const chargePayment: SagaStep<OrderCtx> = {
  name: 'ChargePayment',
  execute: async ctx => {
    const paymentId = await paymentService.charge(ctx.customerId, ctx.totalAmount, ctx.orderId);
    return { ...ctx, paymentId };
  },
  compensate: async ctx => {
    if (ctx.paymentId) await paymentService.refund(ctx.paymentId, 'Saga rollback');
  },
};

// Step 3: Create shipment (this will fail in our example)
const createShipment: SagaStep<OrderCtx> = {
  name: 'CreateShipment',
  execute: async ctx => {
    const shipmentId = await shippingService.create(ctx.orderId, ctx.items);
    return { ...ctx, shipmentId };
  },
  compensate: async ctx => {
    if (ctx.shipmentId) await shippingService.cancel(ctx.shipmentId);
  },
};

// Step 4: Confirm order
const confirmOrder: SagaStep<OrderCtx> = {
  name: 'ConfirmOrder',
  execute: async ctx => {
    await orderService.confirm(ctx.orderId);
    return ctx;
  },
  compensate: async ctx => {
    await orderService.cancel(ctx.orderId, 'Saga rollback');
  },
};

// ---- Run the saga ----
async function fulfillOrder(order: OrderCtx): Promise<OrderCtx> {
  const saga = new SagaOrchestrator<OrderCtx>()
    .addStep(reserveInventory)  // runs first
    .addStep(chargePayment)     // runs second
    .addStep(createShipment)    // FAILS — triggers rollback
    .addStep(confirmOrder);     // never runs

  return saga.execute(order);
}

// When shippingService throws:
// [Saga] → ReserveInventory    ✓
// [Saga] → ChargePayment       ✓
// [Saga] → CreateShipment      ✗ (throws)
// [Saga] ← Compensating ChargePayment   → refund issued
// [Saga] ← Compensating ReserveInventory → stock released
// throws SagaError('CreateShipment', ...)

try {
  await fulfillOrder({
    orderId: 'order-789', customerId: 'cust-123',
    items: [{ productId: 'sku-1', qty: 2, price: 49.99 }],
    totalAmount: 99.98,
  });
} catch (err) {
  if (err instanceof SagaError) {
    console.error(`Order failed at step: ${err.failedStep}`);
    await notifyCustomer('Your order could not be processed');
  }
}
```

**Saga vs 2PC (Two-Phase Commit):**
- 2PC requires all participants to hold locks during the protocol — impractical across microservices or external APIs (Stripe, FedEx)
- Saga uses **compensating transactions** (business-level undo) — each step has its own local ACID transaction
- Trade-off: saga is **eventually consistent**, not immediately consistent. Compensating transactions must be **idempotent** — the network may retry them on failure

**Compensation order:** Always reverse — last completed step is compensated first. This ensures referential integrity (cancel shipment before issuing refund before releasing inventory).
